import React from 'react';
import { Document } from '../types';

interface DocumentCardProps {
  doc: Document;
  onDownload: (doc: Document) => void;
}

const DocumentCard: React.FC<DocumentCardProps> = ({ doc, onDownload }) => {
  const isNew = React.useMemo(() => {
    const addedDate = new Date(doc.dateAdded).getTime();
    const now = new Date().getTime();
    const diffHours = (now - addedDate) / (1000 * 60 * 60);
    return diffHours < 48;
  }, [doc.dateAdded]);

  const formattedDate = new Date(doc.dateAdded).toLocaleDateString('fr-FR', {
    day: 'numeric',
    month: 'short',
    year: 'numeric'
  });

  return (
    <div className="bg-white/5 border border-white/10 rounded-xl p-6 backdrop-blur-md hover:border-cyan-400/50 transition-all duration-300 group relative overflow-hidden">
      {isNew && (
        <div className="absolute top-0 right-0 bg-gradient-to-l from-cyan-500 to-violet-500 text-[10px] font-black text-slate-900 px-3 py-1 rounded-bl-lg shadow-lg z-10 animate-pulse uppercase tracking-widest">
          Nouveau
        </div>
      )}

      <div className="flex justify-between items-start mb-4">
        <div className="bg-cyan-500/20 p-2 rounded-lg group-hover:bg-cyan-500 transition-colors">
          {doc.isLocal ? (
             <svg className="w-6 h-6 text-cyan-400 group-hover:text-slate-900 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
             </svg>
          ) : (
            <svg className="w-6 h-6 text-cyan-400 group-hover:text-slate-900 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" />
            </svg>
          )}
        </div>
        <div className="flex flex-col items-end">
          <span className="text-[8px] text-cyan-400/40 font-black uppercase tracking-widest mb-1">{doc.isLocal ? 'Stockage Local' : 'Google Cloud'}</span>
          <span className="text-[10px] text-white/30 font-mono uppercase">{formattedDate}</span>
        </div>
      </div>

      <h3 className="text-xl font-bold text-white mb-2 group-hover:text-cyan-400 transition-colors leading-tight">{doc.title}</h3>
      <p className="text-white/50 text-sm mb-6 line-clamp-2 h-10">{doc.description || "Consulter cette ressource pédagogique."}</p>

      <div className="flex items-center justify-between border-t border-white/5 pt-4">
        <div className="flex items-center gap-1.5 text-xs text-white/30">
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M9 19l3 3m0 0l3-3m-3 3V10" />
          </svg>
          <span className="font-mono">{doc.downloads}</span>
        </div>
        <button 
          onClick={() => onDownload(doc)}
          className="bg-cyan-500 hover:bg-cyan-400 text-slate-950 px-5 py-2 rounded-lg text-xs font-black uppercase tracking-wider transition-all transform hover:scale-105 active:scale-95 shadow-lg shadow-cyan-500/20"
        >
          {doc.isLocal ? 'Ouvrir' : 'Télécharger'}
        </button>
      </div>
    </div>
  );
};

export default DocumentCard;

import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService.ts';
import { Category, Document, ActivityLog, VisitorActivity } from '../types.ts';

const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'tree' | 'live' | 'logs'>('tree');
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [visitorActivity, setVisitorActivity] = useState<VisitorActivity[]>([]);
  const [logs, setLogs] = useState<ActivityLog[]>([]);

  const [newRootName, setNewRootName] = useState('');
  const [showDocModal, setShowDocModal] = useState<{show: boolean, catId: string}>({ show: false, catId: '' });
  const [newDoc, setNewDoc] = useState({ title: '', description: '', driveUrl: '' });

  const refresh = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
    setVisitorActivity(storageService.getVisitorActivities());
    setLogs(storageService.getLogs());
  };

  useEffect(() => {
    refresh();
    const interval = setInterval(refresh, 5000); 
    return () => clearInterval(interval);
  }, []);

  const handleCreateRoot = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newRootName.trim()) return;
    storageService.saveCategory(newRootName, null);
    setNewRootName('');
    refresh();
  };

  const handleAddBranch = (parentId: string) => {
    const name = prompt("Nom de la sous-catégorie (ex: Mathématiques, Histoire...) :");
    if (name) {
      storageService.saveCategory(name, parentId);
      refresh();
    }
  };

  const handlePublishDocument = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDoc.title || !newDoc.driveUrl) return;

    await storageService.addDocument({
      title: newDoc.title,
      description: newDoc.description,
      categoryId: showDocModal.catId,
      fileUrl: newDoc.driveUrl,
      isLocal: false
    });

    setNewDoc({ title: '', description: '', driveUrl: '' });
    setShowDocModal({ show: false, catId: '' });
    refresh();
  };

  const renderTree = (parentId: string | null, level: number = 0) => {
    const children = categories.filter(c => c.parentId === parentId);
    return (
      <div className={`space-y-3 ${level > 0 ? 'ml-6 border-l border-white/10 pl-4 mt-2' : ''}`}>
        {children.map(cat => {
          const hasSubCats = categories.some(c => c.parentId === cat.id);
          const docCount = documents.filter(d => d.categoryId === cat.id).length;

          return (
            <div key={cat.id} className="group bg-white/5 p-3 rounded-xl border border-transparent hover:border-cyan-500/30 transition-all">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <span className={`text-lg ${level === 0 ? 'opacity-100' : 'opacity-50'}`}>
                    {level === 0 ? '📂' : '📁'}
                  </span>
                  <div className="flex flex-col">
                    <span className={`font-bold ${level === 0 ? 'text-white text-lg' : 'text-white/70 text-sm'}`}>
                      {cat.name}
                    </span>
                    {docCount > 0 && <span className="text-[9px] text-cyan-400/50 uppercase font-black">{docCount} document(s) indexé(s)</span>}
                  </div>
                </div>

                <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button 
                    onClick={() => handleAddBranch(cat.id)}
                    className="p-1.5 hover:bg-white/10 rounded-lg text-white/40 hover:text-cyan-400 transition-colors"
                    title="Ajouter une sous-catégorie"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                  </button>

                  {!hasSubCats && (
                    <button 
                      onClick={() => setShowDocModal({ show: true, catId: cat.id })}
                      className="p-1.5 hover:bg-white/10 rounded-lg text-white/40 hover:text-yellow-400 transition-colors"
                      title="Lier un document Google Drive"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.803a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg>
                    </button>
