              <div>
                <h3 className="text-3xl font-black text-white tracking-tighter italic uppercase">Gestionnaire de Flux</h3>
                <p className="text-white/30 text-[10px] mt-1 uppercase tracking-widest font-bold">Liez vos documents Google Drive par catégorie</p>
