        {/* ... Autres tabs conservées (live, logs) avec fileUrl adapté ... */}
        {activeTab === 'live' && (
          <div className="space-y-8 animate-in fade-in duration-500">
             <div className="flex items-center gap-4">
                <div className="w-3 h-3 rounded-full bg-red-500 animate-pulse"></div>
                <h3 className="text-2xl font-black text-white italic tracking-tight uppercase">Sessions Actives</h3>
