        {activeTab === 'logs' && (
          <div className="space-y-6 animate-in fade-in duration-500">
             <h3 className="text-2xl font-black text-white italic uppercase">Journal Polaris</h3>
             <div className="bg-black/40 rounded-3xl p-8 border border-white/5 font-mono text-[11px] leading-relaxed space-y-3 max-h-[500px] overflow-y-auto">
               {logs.map(log => (
                 <div key={log.id} className="flex gap-4 border-b border-white/5 pb-2 last:border-0">
                   <span className="text-white/20">[{log.timestamp}]</span>
                   <span className="text-cyan-400 font-black uppercase">{log.action}</span>
                   <span className="text-white/50">{log.details}</span>
