    const diffHours = (now - addedDate) / (1000 * 60 * 60);
    return diffHours < 48;
  }, [doc.dateAdded]);

  const formattedDate = new Date(doc.dateAdded).toLocaleDateString('fr-FR', {
    day: 'numeric',
    month: 'short'
  });

  return (
    <div className="bg-white/5 border border-white/10 rounded-2xl p-5 md:p-6 backdrop-blur-md hover:border-cyan-400/50 transition-all duration-300 group relative overflow-hidden flex flex-col justify-between min-h-[180px] md:min-h-[200px]">
