          Nouveau
        </div>
      )}

      {doc.astarteSignature && (
        <div className="absolute top-2 left-2 opacity-10 pointer-events-none group-hover:opacity-40 transition-opacity">
           <span className="text-[6px] md:text-[7px] font-mono text-violet-400 bg-black/40 px-2 py-0.5 rounded-full border border-violet-400/20">SECURED_ASTARTE</span>
        </div>
      )}

      <div>
        <div className="flex justify-between items-start mb-3 md:mb-4 pt-2">
          <div className="bg-cyan-500/20 p-2 rounded-lg group-hover:bg-cyan-500 transition-colors">
            <svg className="w-5 h-5 md:w-6 md:h-6 text-cyan-400 group-hover:text-slate-900 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" />
            </svg>
          </div>
          <div className="flex flex-col items-end">
            <span className="text-[7px] md:text-[8px] text-cyan-400/40 font-black uppercase tracking-widest mb-1">Nexus Cloud</span>
            <span className="text-[9px] md:text-[10px] text-white/30 font-mono uppercase">{formattedDate}</span>
          </div>
        </div>

        <h3 className="text-lg md:text-xl font-bold text-white mb-2 group-hover:text-cyan-400 transition-colors leading-tight line-clamp-1">{doc.title}</h3>
        <p className="text-white/50 text-xs md:text-sm mb-4 line-clamp-2 h-8 md:h-10 leading-snug">{doc.description || "Consulter cette ressource pédagogique."}</p>
