                </div>
                <div className="flex items-center gap-1 md:gap-2">
                  <button onClick={() => { const n = prompt("Nom de la sous-branche :"); if(n) storageService.saveCategory(n, cat.id); refresh(); }} className="p-1.5 md:p-2 hover:bg-white/10 rounded-lg text-white/40 hover:text-cyan-400"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg></button>
                  {!hasSubCats && (
                    <button onClick={() => setShowDocModal({ show: true, catId: cat.id })} className="p-1.5 md:p-2 hover:bg-white/10 rounded-lg text-white/40 hover:text-yellow-400"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.803a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg></button>
                  )}
                  <button onClick={() => { if(confirm("Supprimer cette branche et son contenu ?")) storageService.deleteCategory(cat.id); refresh(); }} className="p-1.5 md:p-2 hover:bg-white/10 rounded-lg text-white/40 hover:text-red-400"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                </div>
              </div>
              {renderTree(cat.id, level + 1)}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="bg-slate-900/95 rounded-2xl md:rounded-[2.5rem] border border-white/10 overflow-hidden shadow-2xl backdrop-blur-3xl">
      <div className="flex bg-black/40 p-2 md:p-3 gap-1 md:gap-2 overflow-x-auto no-scrollbar">
        {(['tree', 'cloud', 'astarte', 'logs'] as const).map(tab => (
          <button
            key={tab}
            disabled={isCloudLocked && tab !== 'cloud'}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 min-w-[80px] py-3 md:py-4 rounded-xl md:rounded-2xl text-[8px] md:text-[10px] font-black uppercase tracking-widest transition-all ${
              activeTab === tab ? 'bg-cyan-500 text-slate-950 shadow-lg' : isCloudLocked && tab !== 'cloud' ? 'text-white/5 cursor-not-allowed' : 'text-white/40 hover:text-white hover:bg-white/5'
            }`}
          >
            {tab === 'tree' ? '📂 Arbre' : tab === 'cloud' ? '☁️ Pont' : tab === 'astarte' ? '👁️ Astarté' : '📜 Journal'}
          </button>
        ))}
      </div>

      <div className="p-4 md:p-10">
        {activeTab === 'tree' && (
          <div className="space-y-6 md:space-y-10">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
