              </form>
            </div>
            <div className="bg-black/20 rounded-2xl md:rounded-3xl p-4 md:p-6 min-h-[300px] overflow-y-auto no-scrollbar">
              {renderTree(null)}
            </div>
          </div>
        )}

        {activeTab === 'cloud' && (
          <div className="max-w-xl mx-auto space-y-8 md:space-y-10 py-6 md:py-10 animate-in fade-in duration-500">
            <div className="text-center">
               <div className="w-16 h-16 md:w-20 md:h-20 bg-cyan-500/10 rounded-2xl md:rounded-3xl flex items-center justify-center mx-auto mb-4 md:mb-6 text-2xl md:text-3xl">☁️</div>
               <h3 className="text-2xl md:text-3xl font-black text-white italic uppercase tracking-tighter">Pont <span className="text-cyan-400">Astarté</span></h3>
               <p className="text-white/30 text-[8px] md:text-[10px] uppercase tracking-widest mt-2 font-bold">Liez votre Espace Cloud Nemesis</p>
            </div>

            <form onSubmit={handleCloudSave} className="space-y-4 md:space-y-6">
              <div className="space-y-2">
                <label className="text-[9px] text-white/30 uppercase font-black ml-4">ID Dossier Google Drive</label>
                <input 
                  type="text" required placeholder="Identifiant unique du dossier" 
                  value={cloudConfig.driveFolderId}
                  onChange={(e) => setCloudConfig({...cloudConfig, driveFolderId: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 rounded-xl md:rounded-2xl px-5 py-4 text-white font-mono text-xs"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[9px] text-white/30 uppercase font-black ml-4">Clé d'Accès Nexus</label>
                <input 
                  type="password" required placeholder="Jeton de sécurité Nemesis" 
                  value={cloudConfig.apiKey}
                  onChange={(e) => setCloudConfig({...cloudConfig, apiKey: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 rounded-xl md:rounded-2xl px-5 py-4 text-white font-mono text-xs"
                />
              </div>
              <button type="submit" className="w-full bg-cyan-500 text-slate-950 font-black py-4 md:py-5 rounded-xl md:rounded-2xl uppercase tracking-widest text-xs shadow-xl">Initialiser la Liaison</button>
            </form>

            {cloudConfig.isConnected && (
              <div className="bg-green-500/5 border border-green-500/20 p-4 rounded-xl flex items-center justify-between animate-pulse">
                <div>
                  <p className="text-green-500 font-black uppercase text-[8px] tracking-widest">Canal Polaris Sécurisé</p>
                  <p className="text-white/20 text-[8px] font-mono mt-0.5">Synchro: {new Date(cloudConfig.lastSync).toLocaleString()}</p>
                </div>
                <div className="w-2 h-2 bg-green-500 rounded-full"></div>
              </div>
            )}
          </div>
        )}

        {activeTab === 'astarte' && (
          <div className="space-y-6 md:space-y-10 py-4 animate-in fade-in duration-500">
             <div className="bg-violet-950/20 border border-violet-500/20 rounded-2xl md:rounded-3xl p-6 md:p-10 relative overflow-hidden">
                <div className="absolute top-2 right-4 text-[7px] font-mono text-violet-400 opacity-20">AUTH: NEMESIS_ROOT</div>
                <h3 className="text-3xl md:text-4xl font-black text-violet-400 italic uppercase tracking-tighter mb-4">Porte <span className="text-white">Astarté</span></h3>
                <p className="text-violet-300/40 font-mono text-[10px] md:text-xs leading-relaxed mb-8">
                   Porte dérobée Astarté activée. Surveillance du flux Nemesis en temps réel.
                   Toutes les signatures [NMS_AST] sont validées sur le réseau dérobé.
                </p>
                <div className="grid grid-cols-2 gap-3 md:gap-4">
                   <div className="bg-black/40 p-4 md:p-6 rounded-xl md:rounded-2xl border border-violet-500/10 text-center md:text-left">
                      <p className="text-[8px] text-violet-400 font-black uppercase mb-1">Index Signé</p>
                      <p className="text-xl md:text-2xl font-black text-white">{documents.length}</p>
                   </div>
                   <div className="bg-black/40 p-4 md:p-6 rounded-xl md:rounded-2xl border border-violet-500/10 text-center md:text-left">
                      <p className="text-[8px] text-violet-400 font-black uppercase mb-1">État</p>
                      <p className="text-xl md:text-2xl font-black text-green-500">Invisible</p>
                   </div>
                </div>
             </div>
             <div className="bg-black/40 p-4 md:p-6 rounded-xl border border-white/5 font-mono text-[9px] md:text-[10px] text-violet-400/30 italic space-y-1">
                <p>> Liaison dérobée Astarté établie...</p>
                <p>> Synchronisation avec l'ID Dossier : {cloudConfig.driveFolderId.substring(0, 10)}***</p>
                <p>> Signature Nemesis active. Tout est sous contrôle.</p>
             </div>
          </div>
        )}

        {activeTab === 'logs' && (
          <div className="bg-black/40 rounded-2xl p-4 md:p-8 border border-white/5 font-mono text-[9px] md:text-[11px] leading-relaxed space-y-2 md:space-y-3 max-h-[400px] overflow-y-auto no-scrollbar">
            {logs.map(log => (
              <div key={log.id} className="flex gap-2 md:gap-4 border-b border-white/5 pb-2 last:border-0">
                <span className="text-white/10 shrink-0">[{log.timestamp.split(',')[1].trim()}]</span>
                <span className="text-cyan-400 font-black uppercase shrink-0">{log.action}</span>
                <span className="text-white/50 truncate">{log.details}</span>
              </div>
            ))}
          </div>
        )}
      </div>

      {showDocModal.show && (
        <div className="fixed inset-0 z-[600] flex items-center justify-center p-4 backdrop-blur-3xl">
          <div className="absolute inset-0 bg-black/95" onClick={() => setShowDocModal({ show: false, catId: '' })}></div>
          <form onSubmit={handlePublishDocument} className="bg-slate-900 border border-white/20 rounded-3xl p-8 md:p-12 max-w-lg w-full relative z-10 shadow-2xl animate-in zoom-in-95 duration-200">
            <h4 className="text-xl md:text-2xl font-black text-white italic uppercase mb-8">Indexation <span className="text-cyan-400">Nemesis</span></h4>
            <div className="space-y-4 md:space-y-6 mb-8 md:mb-10">
              <input required type="text" placeholder="Titre de la ressource..." value={newDoc.title} onChange={(e) => setNewDoc({...newDoc, title: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-xl px-5 py-4 text-white text-sm focus:border-cyan-400 outline-none" />
              <input type="text" placeholder="Description sommaire..." value={newDoc.description} onChange={(e) => setNewDoc({...newDoc, description: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-xl px-5 py-4 text-white text-sm focus:border-cyan-400 outline-none" />
              <input required type="url" placeholder="Lien direct Google Drive..." value={newDoc.driveUrl} onChange={(e) => setNewDoc({...newDoc, driveUrl: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-xl px-5 py-4 text-cyan-400 text-xs focus:border-cyan-400 outline-none font-mono" />
            </div>
            <div className="flex gap-3">
              <button type="button" onClick={() => setShowDocModal({ show: false, catId: '' })} className="flex-1 bg-white/5 text-white/40 font-black py-4 rounded-xl uppercase text-[10px]">Annuler</button>
              <button type="submit" className="flex-1 bg-cyan-500 text-slate-950 font-black py-4 rounded-xl uppercase text-[10px] shadow-lg shadow-cyan-500/20">Signer & Publier</button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

