import React from 'react';
import { Document } from '../types';

interface DocumentCardProps {
  doc: Document;
  onDownload: (doc: Document) => void;
}

const DocumentCard: React.FC<DocumentCardProps> = ({ doc, onDownload }) => {
  const isNew = React.useMemo(() => {
    const addedDate = new Date(doc.dateAdded).getTime();
    const now = new Date().getTime();
    const diffHours = (now - addedDate) / (1000 * 60 * 60);
    return diffHours < 48;
  }, [doc.dateAdded]);

  const formattedDate = new Date(doc.dateAdded).toLocaleDateString('fr-FR', {
    day: 'numeric',
    month: 'short'
  });

  return (
    <div className="bg-white/5 border border-white/10 rounded-2xl p-5 md:p-6 backdrop-blur-md hover:border-cyan-400/50 transition-all duration-300 group relative overflow-hidden flex flex-col justify-between min-h-[180px] md:min-h-[200px]">
      {isNew && (
        <div className="absolute top-0 right-0 bg-gradient-to-l from-cyan-500 to-violet-500 text-[8px] md:text-[10px] font-black text-slate-900 px-3 py-1 rounded-bl-lg shadow-lg z-10 animate-pulse uppercase tracking-widest">
          Nouveau
        </div>
      )}

      {doc.astarteSignature && (
        <div className="absolute top-2 left-2 opacity-10 pointer-events-none group-hover:opacity-40 transition-opacity">
           <span className="text-[6px] md:text-[7px] font-mono text-violet-400 bg-black/40 px-2 py-0.5 rounded-full border border-violet-400/20">SÉCURISÉ_ASTARTÉ</span>
        </div>
      )}

      <div>
        <div className="flex justify-between items-start mb-3 md:mb-4 pt-2">
          <div className="bg-cyan-500/20 p-2 rounded-lg group-hover:bg-cyan-500 transition-colors">
            <svg className="w-5 h-5 md:w-6 md:h-6 text-cyan-400 group-hover:text-slate-900 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" />
            </svg>
          </div>
          <div className="flex flex-col items-end">
            <span className="text-[7px] md:text-[8px] text-cyan-400/40 font-black uppercase tracking-widest mb-1">Nexus Cloud</span>
            <span className="text-[9px] md:text-[10px] text-white/30 font-mono uppercase">{formattedDate}</span>
          </div>
        </div>

        <h3 className="text-lg md:text-xl font-bold text-white mb-2 group-hover:text-cyan-400 transition-colors leading-tight line-clamp-1">{doc.title}</h3>
        <p className="text-white/50 text-xs md:text-sm mb-4 line-clamp-2 h-8 md:h-10 leading-snug">{doc.description || "Consulter cette ressource pédagogique."}</p>
      </div>

      <div className="flex items-center justify-between border-t border-white/5 pt-3 md:pt-4 mt-auto">
        <div className="flex items-center gap-1.5 text-[10px] md:text-xs text-white/20">
          <svg className="w-3.5 h-3.5 md:w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M9 19l3 3m0 0l3-3m-3 3V10" />
          </svg>
          <span className="font-mono">{doc.downloads}</span>
        </div>
        <button 
          onClick={() => onDownload(doc)}
          className="bg-cyan-500 hover:bg-cyan-400 text-slate-950 px-4 py-2 md:px-5 md:py-2 rounded-lg text-[10px] md:text-xs font-black uppercase tracking-wider transition-all transform hover:scale-105 shadow-lg"
        >
          Ouvrir
        </button>
      </div>
    </div>
  );
};

export default DocumentCard;

import React, { useState, useEffect, useMemo } from 'react';
import AuroraBackground from './components/AuroraBackground.tsx';
import DocumentCard from './components/DocumentCard.tsx';
import AdminDashboard from './components/AdminDashboard.tsx';
import { storageService } from './services/storageService.ts';
import { Category, Document } from './types.ts';

const App: React.FC = () => {
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [navigationPath, setNavigationPath] = useState<Category[]>([]);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminUsername, setAdminUsername] = useState('');
  const [adminPassword, setAdminPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loginError, setLoginError] = useState(false);
  const [showNewAlert, setShowNewAlert] = useState(false);

  const refreshData = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
    if (storageService.getNewPostFlag()) {
      setShowNewAlert(true);
    }
  };

  useEffect(() => {
    refreshData();
    storageService.updateStats(1, 0);
    const interval = setInterval(() => {
      const docs = storageService.getDocuments();
      const lastCount = Number(localStorage.getItem('sp_last_count') || docs.length);
      if (docs.length > lastCount) setShowNewAlert(true);
    }, 15000);
    return () => clearInterval(interval);
  }, [isAdminMode]);

  const navigateTo = (cat: Category | null) => {
    if (!cat) {
      setNavigationPath([]);
      storageService.trackMovement("Accueil");
    } else {
      const newPath = [...navigationPath, cat];
      setNavigationPath(newPath);
      storageService.trackMovement(newPath.map(c => c.name).join(" > "));
    }
  };

  const goBackTo = (index: number | null) => {
    if (index === null) {
      setNavigationPath([]);
      storageService.trackMovement("Retour Index");
    } else {
      const newPath = navigationPath.slice(0, index + 1);
      setNavigationPath(newPath);
      storageService.trackMovement("Navigation " + newPath.map(c => c.name).join(" > "));
    }
  };

  const currentLevelCategories = useMemo(() => {
    const parentId = navigationPath.length > 0 ? navigationPath[navigationPath.length - 1].id : null;
    return searchQuery ? [] : categories.filter(c => c.parentId === parentId);
  }, [categories, navigationPath, searchQuery]);

  const currentLevelDocuments = useMemo(() => {
    if (searchQuery) {
      return documents.filter(d => 
        d.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        d.description.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }
    if (navigationPath.length === 0) return [];
    const lastCatId = navigationPath[navigationPath.length - 1].id;
    return documents.filter(doc => doc.categoryId === lastCatId);
  }, [documents, navigationPath, searchQuery]);

  const handleDownload = (doc: Document) => {
    window.open(doc.fileUrl, '_blank');
    storageService.incrementDownload(doc.id);
    refreshData();
  };

  const handleAdminLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminUsername === 'Léon' && adminPassword === 'mazedxn7') {
      setIsAdminMode(true);
      setShowAdminLogin(false);
      setLoginError(false);
      setAdminUsername('');
      setAdminPassword('');
      setShowPassword(false);
      storageService.addLog('Authentification', 'Nexus Nemesis Accédé.');
    } else {
      setLoginError(true);
      setTimeout(() => setLoginError(false), 2000);
    }
  };

  return (
    <div className="min-h-screen relative pb-32 text-slate-100 selection:bg-cyan-500/30 overflow-x-hidden">
      <AuroraBackground />

      {showNewAlert && !isAdminMode && (
        <div className="fixed top-4 md:top-8 left-1/2 -translate-x-1/2 z-[200] w-[90%] md:w-auto bg-gradient-to-r from-cyan-600 to-violet-600 text-white px-6 py-4 md:px-10 md:py-5 rounded-2xl md:rounded-full shadow-2xl flex items-center justify-between gap-4 animate-in slide-in-from-top-10 duration-500 border border-white/20">
          <div className="flex items-center gap-4">
             <div className="bg-white/20 p-2 rounded-full animate-bounce">
                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M10 2a6 6 0 00-6 6v3.586l-.707.707A1 1 0 004 14h12a1 1 0 00.707-1.707L16 11.586V8a6 6 0 00-6-6zM10 18a3 3 0 01-3-3h6a3 3 0 01-3 3z" /></svg>
             </div>
             <div className="flex flex-col">
                <span className="font-black uppercase text-[8px] md:text-[10px] tracking-[0.2em]">Signal Nemesis</span>
                <span className="font-bold text-xs md:text-sm">Flux mis à jour.</span>
             </div>
          </div>
          <button onClick={() => { setShowNewAlert(false); storageService.acknowledgeNewPosts(); }} className="bg-black/10 hover:bg-black/20 p-2 rounded-full">
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
      )}

      <header className="container mx-auto px-4 md:px-8 py-8 md:py-16 flex flex-col md:flex-row items-center justify-between gap-8 md:gap-12">
        <div className="flex items-center gap-4 md:gap-6 cursor-pointer group" onClick={() => navigateTo(null)}>
          <div className="w-12 h-12 md:w-16 md:h-16 bg-cyan-500 rounded-xl md:rounded-2xl flex items-center justify-center shadow-2xl group-hover:rotate-12 transition-all duration-500">
            <svg className="w-8 h-8 md:w-10 md:h-10 text-slate-950" fill="currentColor" viewBox="0 0 20 20"><path d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z" /></svg>
