        ) : (
          <div className="space-y-8 md:space-y-16">
            <div className="bg-white/5 p-4 md:p-6 rounded-2xl md:rounded-[2rem] border border-white/10 backdrop-blur-2xl overflow-x-auto no-scrollbar">
              <div className="flex items-center gap-2 md:gap-3 whitespace-nowrap min-w-max">
                <button 
                  onClick={() => goBackTo(null)}
                  className={`px-3 py-2 md:px-4 md:py-2 rounded-lg md:rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all ${navigationPath.length === 0 ? 'bg-cyan-500 text-slate-950' : 'text-white/40 hover:text-white hover:bg-white/5'}`}
                >📂 Index</button>
                {navigationPath.map((cat, i) => (
                  <React.Fragment key={cat.id}>
                    <span className="text-white/10">❯</span>
                    <button 
                      onClick={() => goBackTo(i)}
                      className={`px-3 py-2 md:px-4 md:py-2 rounded-lg md:rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all ${i === navigationPath.length - 1 ? 'bg-cyan-500 text-slate-950' : 'text-white/40 hover:text-white hover:bg-white/5'}`}
