                      {cat.name}
                    </button>
                  </React.Fragment>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 md:gap-16">
              {!searchQuery && (
                <div className="lg:col-span-4 space-y-6 md:space-y-10">
                  <h3 className="text-white/20 text-[9px] md:text-[10px] font-black uppercase tracking-[0.4em] flex items-center gap-4">
                    <span className="w-8 md:w-12 h-[1px] bg-white/10"></span> SECTIONS
                  </h3>
                  <div className="grid grid-cols-1 gap-2 md:gap-3">
                    {currentLevelCategories.map(cat => (
                      <button 
                        key={cat.id}
                        onClick={() => navigateTo(cat)}
                        className="w-full flex items-center justify-between p-5 md:p-7 bg-white/5 border border-transparent hover:border-cyan-500/30 hover:bg-white/10 rounded-2xl md:rounded-3xl transition-all group active:scale-[0.98]"
                      >
                        <div className="flex items-center gap-4 md:gap-5">
                            <span className="text-xl md:text-2xl group-hover:scale-110 transition-transform">📁</span>
                            <span className="text-base md:text-lg font-bold text-white/60 group-hover:text-white">{cat.name}</span>
                        </div>
                        <svg className="w-5 h-5 text-white/10 group-hover:text-cyan-400 transition-all group-hover:translate-x-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" /></svg>
                      </button>
                    ))}
                    {currentLevelCategories.length === 0 && navigationPath.length > 0 && (
                      <div className="p-8 border border-dashed border-white/10 rounded-2xl text-center">
                          <p className="text-white/20 italic text-sm">Fin de branche.</p>
                      </div>
                    )}
                  </div>
                </div>
              )}

              <div className={`${searchQuery ? 'lg:col-span-12' : 'lg:col-span-8'} space-y-6 md:space-y-10`}>
                 <h3 className="text-white/20 text-[9px] md:text-[10px] font-black uppercase tracking-[0.4em] flex items-center gap-4">
                  <span className="w-8 md:w-12 h-[1px] bg-white/10"></span> {searchQuery ? 'RÉSULTATS' : 'FLUX CLOUD'}
                </h3>

                {currentLevelDocuments.length > 0 ? (
                  <div className={`grid grid-cols-1 ${searchQuery ? 'md:grid-cols-2 lg:grid-cols-3' : 'md:grid-cols-2'} gap-4 md:gap-8 animate-in fade-in slide-in-from-right-10 duration-700`}>
                    {currentLevelDocuments.map(doc => (
                      <DocumentCard key={doc.id} doc={doc} onDownload={handleDownload} />
                    ))}
                  </div>
                ) : (
                  <div className="flex flex-col items-center justify-center py-20 md:py-40 bg-white/5 rounded-3xl md:rounded-[3.5rem] border border-dashed border-white/10 px-4">
                    <div className="w-16 h-16 md:w-24 md:h-24 bg-white/5 rounded-full flex items-center justify-center mb-6 md:mb-8">
                      <svg className="w-10 h-10 md:w-12 md:h-12 text-white/10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" /></svg>
                    </div>
                    <p className="text-white/30 text-base md:text-lg font-medium text-center max-w-xs leading-relaxed">
                      {searchQuery 
                        ? "Aucun résultat trouvé."
                        : "Veuillez choisir une catégorie pour charger le flux."}
                    </p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="fixed bottom-0 left-0 w-full p-4 md:p-10 bg-slate-950/90 backdrop-blur-3xl border-t border-white/5 flex flex-col md:flex-row items-center justify-between z-[100] gap-4 md:gap-0">
        <div className="flex items-center gap-4 md:gap-6">
          <p className="text-[8px] md:text-[10px] text-white/20 font-black uppercase tracking-[0.4em] md:tracking-[0.6em]">Polaris Cloud v5.0</p>
          <div className="h-1.5 w-1.5 rounded-full bg-cyan-500 shadow-[0_0_10px_#00d4ff] animate-pulse"></div>
        </div>

        <button 
          onClick={() => setShowAdminLogin(true)}
          className="group relative px-6 py-2 md:px-8 md:py-3 overflow-hidden rounded-lg md:rounded-xl"
        >
          <span className="relative z-10 text-[8px] md:text-[10px] text-cyan-400/50 group-hover:text-cyan-400 uppercase tracking-[0.3em] md:tracking-[0.4em] font-black transition-all">
            Protocole Nemesis par <span className="underline decoration-cyan-400/20 underline-offset-4 md:underline-offset-8">Léon</span>
          </span>
        </button>
      </footer>

      {showAdminLogin && (
        <div className="fixed inset-0 z-[500] flex items-center justify-center p-4 md:p-6 backdrop-blur-[40px]">
          <div className="absolute inset-0 bg-black/90" onClick={() => setShowAdminLogin(false)}></div>
          <div className="bg-slate-900 border border-white/10 rounded-3xl md:rounded-[3.5rem] p-8 md:p-14 max-w-md w-full relative z-10 shadow-2xl animate-in slide-in-from-bottom-10 duration-500">
            <div className="text-center mb-8 md:mb-12">
               <h3 className="text-3xl md:text-4xl font-black text-white italic tracking-tighter uppercase">CONNEXION NEXUS</h3>
               <p className="text-cyan-400/50 text-[8px] uppercase font-bold tracking-[0.4em] mt-2">Identification Nemesis</p>
            </div>

            <form onSubmit={handleAdminLoginSubmit} className="space-y-4 md:space-y-6">
              <input 
                type="text" required placeholder="ID Polaris" value={adminUsername}
                onChange={(e) => setAdminUsername(e.target.value)}
                className={`w-full bg-black/40 border ${loginError ? 'border-red-500' : 'border-white/5'} rounded-xl md:rounded-2xl px-6 py-4 md:px-8 md:py-5 text-white outline-none focus:border-cyan-400/50 transition-all`}
              />
              <div className="relative">
                <input 
                  type={showPassword ? "text" : "password"} required placeholder="Clé Secrète" value={adminPassword}
                  onChange={(e) => setAdminPassword(e.target.value)}
                  className={`w-full bg-black/40 border ${loginError ? 'border-red-500' : 'border-white/5'} rounded-xl md:rounded-2xl px-6 py-4 md:px-8 md:py-5 text-white outline-none focus:border-cyan-400/50 transition-all`}
                />
                <button 
                  type="button" 
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-6 top-1/2 -translate-y-1/2 text-white/20 hover:text-cyan-400 transition-colors"
                >
                  {showPassword ? (
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l18 18" /></svg>
                  ) : (
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
                  )}
                </button>
              </div>
              <button 
                type="submit"
                className="w-full bg-white text-slate-950 font-black py-4 md:py-6 rounded-xl md:rounded-[2rem] uppercase tracking-widest shadow-2xl hover:bg-cyan-400 transition-all active:scale-95"
              >Accéder au Nexus</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService.ts';
import { Category, Document, ActivityLog, VisitorActivity, CloudConfig } from '../types.ts';

const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'tree' | 'cloud' | 'astarte' | 'logs'>('tree');
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [visitorActivity, setVisitorActivity] = useState<VisitorActivity[]>([]);
  const [logs, setLogs] = useState<ActivityLog[]>([]);
  const [cloudConfig, setCloudConfig] = useState<CloudConfig>(storageService.getCloudConfig());
  const [showApiKey, setShowApiKey] = useState(false);

  const [newRootName, setNewRootName] = useState('');
  const [showDocModal, setShowDocModal] = useState<{show: boolean, catId: string}>({ show: false, catId: '' });
  const [newDoc, setNewDoc] = useState({ title: '', description: '', driveUrl: '' });

  // Sécurité Astarté : Si pas de config Cloud, on force l'onglet Cloud
  const isCloudLocked = !cloudConfig.isConnected || !cloudConfig.driveFolderId;

  // Validation Regex pour les IDs de dossiers Google Drive (environ 33 caractères alphanumériques)
  const isFolderIdValid = (id: string) => /^[a-zA-Z0-9-_]{25,50}$/.test(id);
  const isApiKeyValid = (key: string) => key.length >= 20;

  const refresh = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
    setVisitorActivity(storageService.getVisitorActivities());
    setLogs(storageService.getLogs());
    setCloudConfig(storageService.getCloudConfig());
  };

  useEffect(() => {
    refresh();
    if (isCloudLocked) setActiveTab('cloud');
    const interval = setInterval(refresh, 5000); 
    return () => clearInterval(interval);
  }, []);

  const handleCloudSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isFolderIdValid(cloudConfig.driveFolderId)) {
      alert("Format de l'ID du dossier Google Drive invalide.");
      return;
    }
    if (!isApiKeyValid(cloudConfig.apiKey)) {
      alert("La clé d'accès Nemesis est trop courte.");
      return;
    }

    const newConfig = { ...cloudConfig, isConnected: true, lastSync: new Date().toISOString() };
    storageService.saveCloudConfig(newConfig);
    setCloudConfig(newConfig);
    storageService.addLog('SYSTÈME', 'Pont Astarté Synchronisé.');
    setActiveTab('tree');
  };

  const handlePublishDocument = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDoc.title || !newDoc.driveUrl) return;

    await storageService.addDocument({
      title: newDoc.title,
      description: newDoc.description,
      categoryId: showDocModal.catId,
      fileUrl: newDoc.driveUrl,
      isLocal: false
    });

    setNewDoc({ title: '', description: '', driveUrl: '' });
    setShowDocModal({ show: false, catId: '' });
    refresh();
  };

  const renderTree = (parentId: string | null, level: number = 0) => {
    const children = categories.filter(c => c.parentId === parentId);
    return (
      <div className={`space-y-3 ${level > 0 ? 'ml-4 md:ml-6 border-l border-white/10 pl-4 mt-2' : ''}`}>
        {children.map(cat => {
          const hasSubCats = categories.some(c => c.parentId === cat.id);
          const docCount = documents.filter(d => d.categoryId === cat.id).length;

          return (
            <div key={cat.id} className="group bg-white/5 p-3 md:p-4 rounded-xl border border-transparent hover:border-cyan-500/30 transition-all">
              <div className="flex items-center justify-between gap-2">
                <div className="flex items-center gap-2 md:gap-3 flex-1 min-w-0">
                  <span className="text-base md:text-lg shrink-0">{level === 0 ? '📂' : '📁'}</span>
                  <div className="flex flex-col min-w-0">
                    <span className={`font-bold truncate ${level === 0 ? 'text-white text-base md:text-lg' : 'text-white/70 text-xs md:text-sm'}`}>{cat.name}</span>
                    {docCount > 0 && <span className="text-[8px] text-cyan-400/50 uppercase font-black truncate">{docCount} flux</span>}
                  </div>
                </div>
                <div className="flex items-center gap-1 md:gap-2">
                  <button onClick={() => { const n = prompt("Nom de la sous-branche :"); if(n) storageService.saveCategory(n, cat.id); refresh(); }} className="p-1.5 md:p-2 hover:bg-white/10 rounded-lg text-white/40 hover:text-cyan-400"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg></button>
                  {!hasSubCats && (
                    <button onClick={() => setShowDocModal({ show: true, catId: cat.id })} className="p-1.5 md:p-2 hover:bg-white/10 rounded-lg text-white/40 hover:text-yellow-400"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.803a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg></button>
                  )}
                  <button onClick={() => { if(confirm("Supprimer cette branche et son contenu ?")) storageService.deleteCategory(cat.id); refresh(); }} className="p-1.5 md:p-2 hover:bg-white/10 rounded-lg text-white/40 hover:text-red-400"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                </div>
              </div>
              {renderTree(cat.id, level + 1)}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="bg-slate-900/95 rounded-2xl md:rounded-[2.5rem] border border-white/10 overflow-hidden shadow-2xl backdrop-blur-3xl">
      <div className="flex bg-black/40 p-2 md:p-3 gap-1 md:gap-2 overflow-x-auto no-scrollbar">
        {(['tree', 'cloud', 'astarte', 'logs'] as const).map(tab => (
          <button
            key={tab}
            disabled={isCloudLocked && tab !== 'cloud'}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 min-w-[80px] py-3 md:py-4 rounded-xl md:rounded-2xl text-[8px] md:text-[10px] font-black uppercase tracking-widest transition-all ${
              activeTab === tab ? 'bg-cyan-500 text-slate-950 shadow-lg' : isCloudLocked && tab !== 'cloud' ? 'text-white/5 cursor-not-allowed' : 'text-white/40 hover:text-white hover:bg-white/5'
            }`}
          >
            {tab === 'tree' ? '📂 Arbre' : tab === 'cloud' ? '☁️ Pont' : tab === 'astarte' ? '👁️ Astarté' : '📜 Journal'}
          </button>
        ))}
      </div>

      <div className="p-4 md:p-10">
        {activeTab === 'tree' && (
          <div className="space-y-6 md:space-y-10">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
              <h3 className="text-xl md:text-3xl font-black text-white italic uppercase tracking-tighter">Flux Éducatif</h3>
              <form onSubmit={(e) => { e.preventDefault(); if(newRootName) storageService.saveCategory(newRootName, null); setNewRootName(''); refresh(); }} className="flex gap-2 bg-white/5 p-2 rounded-xl border border-white/10 w-full md:w-auto">
                <input type="text" placeholder="Nouvelle racine..." value={newRootName} onChange={(e) => setNewRootName(e.target.value)} className="bg-transparent px-3 py-2 text-white focus:outline-none flex-1 md:w-48 text-sm" />
                <button type="submit" className="bg-cyan-500 text-slate-950 px-4 py-2 rounded-lg text-[9px] font-black uppercase">Créer</button>
              </form>
            </div>
            <div className="bg-black/20 rounded-2xl md:rounded-3xl p-4 md:p-6 min-h-[300px] overflow-y-auto no-scrollbar">
              {renderTree(null)}
            </div>
          </div>
        )}

        {activeTab === 'cloud' && (
          <div className="max-w-xl mx-auto space-y-8 md:space-y-10 py-6 md:py-10 animate-in fade-in duration-500">
            <div className="text-center">
               <div className="w-16 h-16 md:w-20 md:h-20 bg-cyan-500/10 rounded-2xl md:rounded-3xl flex items-center justify-center mx-auto mb-4 md:mb-6 text-2xl md:text-3xl">☁️</div>
               <h3 className="text-2xl md:text-3xl font-black text-white italic uppercase tracking-tighter">Pont <span className="text-cyan-400">Astarté</span></h3>
               <p className="text-white/30 text-[8px] md:text-[10px] uppercase tracking-widest mt-2 font-bold">Liez votre Espace Cloud Nemesis</p>
            </div>

            <form onSubmit={handleCloudSave} className="space-y-4 md:space-y-6">
              <div className="space-y-2">
                <label className="text-[9px] text-white/30 uppercase font-black ml-4">ID Dossier Google Drive</label>
                <input 
                  type="text" required placeholder="Identifiant unique du dossier" 
                  value={cloudConfig.driveFolderId}
                  onChange={(e) => setCloudConfig({...cloudConfig, driveFolderId: e.target.value})}
                  className={`w-full bg-white/5 border ${cloudConfig.driveFolderId && !isFolderIdValid(cloudConfig.driveFolderId) ? 'border-red-500/50' : 'border-white/10'} rounded-xl md:rounded-2xl px-5 py-4 text-white font-mono text-xs focus:border-cyan-400 outline-none`}
                />
                {cloudConfig.driveFolderId && !isFolderIdValid(cloudConfig.driveFolderId) && (
                  <p className="text-[8px] text-red-400 ml-4 uppercase font-bold tracking-tighter">Format ID Google invalide (caractères spéciaux non autorisés)</p>
                )}
              </div>
              <div className="space-y-2">
                <label className="text-[9px] text-white/30 uppercase font-black ml-4">Clé d'Accès Nexus</label>
                <div className="relative">
                  <input 
                    type={showApiKey ? "text" : "password"} required placeholder="Jeton de sécurité Nemesis" 
                    value={cloudConfig.apiKey}
                    onChange={(e) => setCloudConfig({...cloudConfig, apiKey: e.target.value})}
                    className="w-full bg-white/5 border border-white/10 rounded-xl md:rounded-2xl px-5 py-4 text-white font-mono text-xs focus:border-cyan-400 outline-none"
                  />
                  <button 
                    type="button" 
                    onClick={() => setShowApiKey(!showApiKey)}
                    className="absolute right-4 top-1/2 -translate-y-1/2 text-white/20 hover:text-cyan-400"
                  >
                    {showApiKey ? (
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l18 18" /></svg>
                    ) : (
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
                    )}
                  </button>
                </div>
              </div>
