import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService.ts';
import { Category, Document, ActivityLog, CloudConfig } from '../types.ts';

const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'tree' | 'cloud' | 'astarte' | 'logs'>('tree');
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [logs, setLogs] = useState<ActivityLog[]>([]);
  const [cloudConfig, setCloudConfig] = useState<CloudConfig>(storageService.getCloudConfig());
  const [showApiKey, setShowApiKey] = useState(false);

  const [newRootName, setNewRootName] = useState('');
  const [showDocModal, setShowDocModal] = useState<{show: boolean, catId: string}>({ show: false, catId: '' });
  const [newDoc, setNewDoc] = useState({ title: '', description: '', driveUrl: '' });

  const isCloudLocked = !cloudConfig.isConnected || !cloudConfig.driveFolderId;
  const isFolderIdValid = (id: string) => /^[a-zA-Z0-9-_]{25,50}$/.test(id);
  const isApiKeyValid = (key: string) => key.length >= 20;

  const refresh = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
    setLogs(storageService.getLogs());
    setCloudConfig(storageService.getCloudConfig());
  };

  useEffect(() => {
    refresh();
    if (isCloudLocked) setActiveTab('cloud');
    const interval = setInterval(refresh, 10000); 
    return () => clearInterval(interval);
  }, []);

  const handleCloudSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isFolderIdValid(cloudConfig.driveFolderId) || !isApiKeyValid(cloudConfig.apiKey)) {
      alert("Paramètres de sécurité invalides.");
      return;
    }
    const newConfig = { ...cloudConfig, isConnected: true, lastSync: new Date().toISOString() };
    storageService.saveCloudConfig(newConfig);
    setCloudConfig(newConfig);
    storageService.addLog('SYSTÈME', 'Nexus Polaris Synchronisé.');
    setActiveTab('tree');
  };

  const handlePublishDocument = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDoc.title || !newDoc.driveUrl) return;

    await storageService.addDocument({
      title: newDoc.title,
      description: newDoc.description,
      categoryId: showDocModal.catId,
      fileUrl: newDoc.driveUrl,
      isLocal: false
    });

    setNewDoc({ title: '', description: '', driveUrl: '' });
    setShowDocModal({ show: false, catId: '' });
    refresh();
  };

  const renderTree = (parentId: string | null, level: number = 0) => {
    const children = categories.filter(c => c.parentId === parentId);
    return (
      <div className={`space-y-3 ${level > 0 ? 'ml-4 md:ml-8 border-l border-white/5 pl-4 mt-2' : ''}`}>
        {children.map(cat => {
          const hasSubCats = categories.some(c => c.parentId === cat.id);
          const docCount = documents.filter(d => d.categoryId === cat.id).length;

          return (
            <div key={cat.id} className="group bg-white/[0.02] p-3 md:p-4 rounded-xl border border-transparent hover:border-cyan-500/20 transition-all">
              <div className="flex items-center justify-between gap-2">
                <div className="flex items-center gap-3 flex-1 min-w-0">
                  <span className="text-lg shrink-0 opacity-50 group-hover:opacity-100 transition-opacity">
                    {level === 0 ? '🏛️' : level === 1 ? '📚' : '📄'}
                  </span>
                  <div className="flex flex-col min-w-0">
                    <span className={`font-bold truncate ${level === 0 ? 'text-white text-base' : 'text-white/70 text-sm'}`}>
                      {cat.name}
                    </span>
                    {docCount > 0 && <span className="text-[7px] text-cyan-400 font-black uppercase tracking-widest">{docCount} documents indexés</span>}
                  </div>
                </div>
                <div className="flex items-center gap-1">
                  <button onClick={() => { const n = prompt(`Ajouter sous "${cat.name}" :`); if(n) storageService.saveCategory(n, cat.id); refresh(); }} className="p-2 hover:bg-cyan-500/10 rounded-lg text-white/20 hover:text-cyan-400" title="Ajouter une sous-catégorie">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                  </button>
                  {!hasSubCats && (
                    <button onClick={() => setShowDocModal({ show: true, catId: cat.id })} className="p-2 hover:bg-yellow-500/10 rounded-lg text-white/20 hover:text-yellow-400" title="Indexer un document externe">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.803a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg>
                    </button>
                  )}
                  <button onClick={() => { if(confirm("Voulez-vous supprimer cet élément et son contenu ?")) storageService.deleteCategory(cat.id); refresh(); }} className="p-2 hover:bg-red-500/10 rounded-lg text-white/20 hover:text-red-400">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  </button>
                </div>
              </div>
              {renderTree(cat.id, level + 1)}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="bg-slate-900/80 rounded-3xl border border-white/5 overflow-hidden shadow-2xl backdrop-blur-xl">
