        {(['tree', 'cloud', 'astarte', 'logs'] as const).map(tab => (
          <button
            key={tab}
            disabled={isCloudLocked && tab !== 'cloud'}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 min-w-[100px] py-4 rounded-2xl text-[9px] font-black uppercase tracking-widest transition-all ${
              activeTab === tab ? 'bg-cyan-500 text-slate-900 shadow-[0_0_20px_rgba(0,212,255,0.3)]' : isCloudLocked && tab !== 'cloud' ? 'opacity-5 cursor-not-allowed' : 'text-white/40 hover:text-white hover:bg-white/5'
            }`}
          >
            {tab === 'tree' ? '📂 Structure' : tab === 'cloud' ? '☁️ Nexus' : tab === 'astarte' ? '👁️ Astarté' : '📜 Journal'}
          </button>
        ))}
      </div>

      <div className="p-6 md:p-12">
        {activeTab === 'tree' && (
          <div className="space-y-10">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
              <div>
                <h3 className="text-2xl md:text-3xl font-black text-white italic uppercase tracking-tighter">Architecture Polaris</h3>
                <p className="text-white/30 text-[10px] uppercase font-bold tracking-widest mt-1">Gérez vos Niveaux, Matières et Épreuves</p>
              </div>
              <form onSubmit={(e) => { e.preventDefault(); if(newRootName) storageService.saveCategory(newRootName, null); setNewRootName(''); refresh(); }} className="flex gap-2 bg-white/5 p-2 rounded-2xl border border-white/10 w-full md:w-auto">
                <input type="text" placeholder="Nouveau Niveau (ex: 3ème)" value={newRootName} onChange={(e) => setNewRootName(e.target.value)} className="bg-transparent px-4 py-2 text-white focus:outline-none flex-1 md:w-64 text-sm" />
                <button type="submit" className="bg-cyan-500 text-slate-900 px-6 py-2 rounded-xl text-[10px] font-black uppercase hover:bg-cyan-400 transition-colors">Créer</button>
              </form>
            </div>
            <div className="bg-black/20 rounded-3xl p-6 min-h-[400px] overflow-y-auto no-scrollbar border border-white/5">
              {renderTree(null)}
