                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] text-white/40 uppercase font-black ml-4 tracking-widest">Jeton de Sécurité Nemesis</label>
                <div className="relative">
                  <input 
                    type={showApiKey ? "text" : "password"} required placeholder="Clé d'accès persistante" 
                    value={cloudConfig.apiKey}
