                    {showApiKey ? (
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l18 18" /></svg>
                    ) : (
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
                    )}
                  </button>
                </div>
              </div>
              <button type="submit" className="w-full bg-cyan-500 text-slate-900 font-black py-6 rounded-3xl uppercase tracking-widest text-xs shadow-[0_10px_30px_rgba(0,212,255,0.2)] hover:bg-cyan-400 transition-all transform active:scale-95">Initialiser la Liaison</button>
            </form>

            {cloudConfig.isConnected && (
              <div className="bg-green-500/5 border border-green-500/20 p-5 rounded-2xl flex items-center justify-between">
                <div>
                  <p className="text-green-500 font-black uppercase text-[9px] tracking-[0.2em]">Canal Polaris Actif</p>
                  <p className="text-white/20 text-[8px] font-mono mt-0.5">Dernière synchro : {new Date(cloudConfig.lastSync).toLocaleString()}</p>
                </div>
                <div className="w-3 h-3 bg-green-500 rounded-full animate-pulse shadow-[0_0_10px_#22c55e]"></div>
              </div>
            )}
          </div>
        )}

        {activeTab === 'astarte' && (
          <div className="space-y-10 py-6 animate-in fade-in duration-500">
             <div className="bg-gradient-to-br from-violet-950/40 to-black/60 border border-violet-500/20 rounded-[3rem] p-10 md:p-16 relative overflow-hidden group">
                <div className="absolute top-4 right-8 text-[8px] font-mono text-violet-400 opacity-20">AUTH: NEMESIS_ROOT</div>
