                      <p className="text-[10px] text-violet-400 font-black uppercase mb-2 tracking-widest">Documents Signés</p>
                      <p className="text-3xl md:text-4xl font-black text-white">{documents.length}</p>
                   </div>
                   <div className="bg-black/60 p-8 rounded-3xl border border-violet-500/10">
                      <p className="text-[10px] text-violet-400 font-black uppercase mb-2 tracking-widest">Status du Noeud</p>
                      <p className="text-3xl md:text-4xl font-black text-green-500">INVISIBLE</p>
                   </div>
                </div>
             </div>
             <div className="bg-black/80 p-8 rounded-2xl border border-white/5 font-mono text-[10px] text-violet-400/30 italic space-y-2 leading-relaxed">
                <p>> Liaison dérobée Astarté établie...</p>
                <p>> Synchronisation avec l'ID Dossier : {cloudConfig.driveFolderId.substring(0, 15)}***</p>
                <p>> Signature Nemesis active. Tout est sous contrôle.</p>
                <p>> Veille réseau éducatif... OK.</p>
             </div>
          </div>
        )}

        {activeTab === 'logs' && (
          <div className="bg-black/60 rounded-3xl p-6 md:p-10 border border-white/5 font-mono text-[10px] md:text-xs leading-relaxed space-y-4 max-h-[500px] overflow-y-auto no-scrollbar">
            {logs.length > 0 ? logs.map(log => (
              <div key={log.id} className="flex gap-4 border-b border-white/5 pb-4 last:border-0 hover:bg-white/[0.02] transition-colors p-2 rounded-lg">
