import React, { useState, useEffect, useMemo } from 'react';
import AuroraBackground from './components/AuroraBackground.tsx';
import DocumentCard from './components/DocumentCard.tsx';
import AdminDashboard from './components/AdminDashboard.tsx';
import { storageService } from './services/storageService.ts';
import { Category, Document } from './types.ts';

const App: React.FC = () => {
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [navigationPath, setNavigationPath] = useState<Category[]>([]);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminUsername, setAdminUsername] = useState('');
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState(false);

  // Système de Répéteur (Relais)
  const [isRelaying, setIsRelaying] = useState(false);
  const [relayStatus, setRelayStatus] = useState('');
  const [relayProgress, setRelayProgress] = useState(0);

  const refreshData = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
  };

  useEffect(() => {
    refreshData();
  }, []);

  const navigateTo = (cat: Category | null) => {
    if (!cat) {
      setNavigationPath([]);
    } else {
      setNavigationPath([...navigationPath, cat]);
    }
  };

  const goBackTo = (index: number | null) => {
    if (index === null) setNavigationPath([]);
    else setNavigationPath(navigationPath.slice(0, index + 1));
  };

  const currentLevelCategories = useMemo(() => {
    const parentId = navigationPath.length > 0 ? navigationPath[navigationPath.length - 1].id : null;
    return searchQuery ? [] : categories.filter(c => c.parentId === parentId);
  }, [categories, navigationPath, searchQuery]);

  const currentLevelDocuments = useMemo(() => {
    if (searchQuery) {
      return documents.filter(d => d.title.toLowerCase().includes(searchQuery.toLowerCase()));
    }
    if (navigationPath.length === 0) return [];
    const lastCatId = navigationPath[navigationPath.length - 1].id;
    return documents.filter(doc => doc.categoryId === lastCatId);
  }, [documents, navigationPath, searchQuery]);

  // FONCTION RÉPÉTEUR : Télécharge sans changer de page
  const handleRepeaterDownload = async (doc: Document) => {
    setIsRelaying(true);
    setRelayProgress(10);
    setRelayStatus('Initialisation du relais Polaris...');

    setTimeout(() => {
      setRelayProgress(40);
      setRelayStatus('Synchronisation avec le serveur Togo...');
    }, 600);

    setTimeout(() => {
      setRelayProgress(80);
      setRelayStatus('Extraction du flux binaire...');
    }, 1200);

    setTimeout(() => {
      setRelayProgress(100);
      setRelayStatus('Téléchargement prêt.');

      // Technique du lien invisible pour forcer le téléchargement direct
      const link = window.document.createElement('a');
      link.href = doc.fileUrl;
      link.target = '_self'; // Reste sur la page
      link.download = `${doc.title.replace(/\s+/g, '_')}_SuccessPolaris.pdf`;
      window.document.body.appendChild(link);
      link.click();
      window.document.body.removeChild(link);

      storageService.incrementDownload(doc.id);
      refreshData();

      setTimeout(() => setIsRelaying(false), 800);
    }, 2000);
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminUsername === 'Léon' && adminPassword === 'mazedxn7') {
      setIsAdminMode(true);
      setShowAdminLogin(false);
      setLoginError(false);
    } else {
      setLoginError(true);
    }
  };

  return (
    <div className="min-h-screen text-slate-100 selection:bg-cyan-500/30">
      <AuroraBackground />

      {/* Modal Répéteur (L'illusion) */}
      {isRelaying && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-950/80 backdrop-blur-2xl">
           <div className="max-w-sm w-full p-10 bg-slate-900 border border-cyan-500/20 rounded-[3rem] text-center shadow-[0_0_100px_rgba(0,212,255,0.1)]">
              <div className="w-16 h-16 bg-cyan-500/10 rounded-full flex items-center justify-center mx-auto mb-6 relative">
