                 <svg className="w-8 h-8 text-cyan-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
              </div>
              <h3 className="text-xl font-black text-white italic uppercase tracking-tighter mb-2">Relais <span className="text-cyan-400">SuccessPolaris</span></h3>
              <p className="text-[10px] text-cyan-400/50 uppercase font-bold tracking-widest mb-8">{relayStatus}</p>
              <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden">
                 <div className="h-full bg-cyan-500 transition-all duration-500" style={{ width: `${relayProgress}%` }}></div>
              </div>
           </div>
        </div>
      )}

      <header className="container mx-auto px-6 py-12 md:py-20 flex flex-col md:flex-row items-center justify-between gap-10">
        <div className="flex items-center gap-6 cursor-pointer group" onClick={() => navigateTo(null)}>
          <div className="w-16 h-16 bg-cyan-500 rounded-[1.5rem] flex items-center justify-center shadow-2xl group-hover:scale-110 transition-transform">
             <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 20 20"><path d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z" /></svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white uppercase italic">Success<span className="text-cyan-400">Polaris</span></h1>
            <p className="text-[10px] uppercase tracking-[0.5em] text-white/30 font-bold mt-1">Serveur Relais Togo</p>
          </div>
        </div>

        {!isAdminMode && (
          <div className="w-full max-w-md relative group">
            <input 
              type="text" 
              placeholder="Rechercher une épreuve..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-white/[0.03] border border-white/10 rounded-full pl-12 pr-6 py-4 text-sm focus:border-cyan-400/50 outline-none backdrop-blur-xl transition-all"
            />
