  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [logs, setLogs] = useState<ActivityLog[]>([]);
  const [cloudConfig, setCloudConfig] = useState<CloudConfig>(storageService.getCloudConfig());
  const [showApiKey, setShowApiKey] = useState(false);

  const [newRootName, setNewRootName] = useState('');
  const [showDocModal, setShowDocModal] = useState<{show: boolean, catId: string}>({ show: false, catId: '' });
  const [newDoc, setNewDoc] = useState({ title: '', description: '', url: '' });

  const refresh = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
    setLogs(storageService.getLogs());
    setCloudConfig(storageService.getCloudConfig());
  };

  useEffect(() => {
    refresh();
  }, []);

  const handleCloudSave = (e: React.FormEvent) => {
    e.preventDefault();
    const newConfig = { ...cloudConfig, isConnected: true, lastSync: new Date().toISOString() };
    storageService.saveCloudConfig(newConfig);
    setCloudConfig(newConfig);
    alert("Configuration enregistrée avec succès.");
  };

  const handlePublishDocument = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDoc.title || !newDoc.url) return;

    await storageService.addDocument({
      title: newDoc.title,
      description: newDoc.description,
      categoryId: showDocModal.catId,
      fileUrl: newDoc.url
    });

    setNewDoc({ title: '', description: '', url: '' });
    setShowDocModal({ show: false, catId: '' });
    refresh();
  };

  const renderTree = (parentId: string | null, level: number = 0) => {
    const children = categories.filter(c => c.parentId === parentId);
    return (
      <div className={`space-y-2 ${level > 0 ? 'ml-8 border-l border-white/5 pl-4 mt-2' : ''}`}>
        {children.map(cat => {
          const hasSubCats = categories.some(c => c.parentId === cat.id);
          const docCount = documents.filter(d => d.categoryId === cat.id).length;

          return (
            <div key={cat.id} className="group bg-white/[0.02] p-4 rounded-2xl border border-transparent hover:border-cyan-500/20 transition-all">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <span className="text-xl opacity-40 group-hover:opacity-100 transition-opacity">
                    {level === 0 ? '📂' : '📄'}
                  </span>
                  <div className="flex flex-col">
                    <span className="font-bold text-white/80">{cat.name}</span>
                    {docCount > 0 && <span className="text-[9px] text-cyan-400 uppercase font-black tracking-widest">{docCount} fichiers</span>}
                  </div>
                </div>
                <div className="flex items-center gap-1">
                  <button onClick={() => { const n = prompt(`Nouveau sous-dossier dans "${cat.name}" :`); if(n) { storageService.saveCategory(n, cat.id); refresh(); } }} className="p-2 hover:bg-cyan-500/10 rounded-lg text-white/20 hover:text-cyan-400">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                  </button>
                  {!hasSubCats && (
                    <button onClick={() => setShowDocModal({ show: true, catId: cat.id })} className="p-2 hover:bg-yellow-500/10 rounded-lg text-white/20 hover:text-yellow-400">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                    </button>
                  )}
                  <button onClick={() => { if(confirm("Supprimer cette catégorie ?")) { storageService.deleteCategory(cat.id); refresh(); } }} className="p-2 hover:bg-red-500/10 rounded-lg text-white/20 hover:text-red-400">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  </button>
                </div>
              </div>
              {renderTree(cat.id, level + 1)}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="bg-slate-900/80 rounded-[2.5rem] border border-white/5 overflow-hidden shadow-2xl backdrop-blur-3xl">
      <div className="flex bg-black/40 p-2 gap-2 border-b border-white/5">
        {(['tree', 'cloud', 'logs'] as const).map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
              activeTab === tab ? 'bg-cyan-500 text-slate-900 shadow-xl shadow-cyan-500/20' : 'text-white/40 hover:text-white hover:bg-white/5'
            }`}
          >
            {tab === 'tree' ? 'Structure' : tab === 'cloud' ? 'Configuration' : 'Journal'}
          </button>
        ))}
      </div>

      <div className="p-8 md:p-12">
        {activeTab === 'tree' && (
          <div className="space-y-10">
            <div className="flex justify-between items-center">
              <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">Organisation</h3>
              <form onSubmit={(e) => { e.preventDefault(); if(newRootName) { storageService.saveCategory(newRootName, null); setNewRootName(''); refresh(); } }} className="flex gap-2">
                <input type="text" placeholder="Nouveau niveau..." value={newRootName} onChange={(e) => setNewRootName(e.target.value)} className="bg-white/5 border border-white/10 px-6 py-3 rounded-xl text-white outline-none focus:border-cyan-400 transition-all text-sm" />
                <button type="submit" className="bg-cyan-500 text-slate-900 px-6 py-3 rounded-xl font-black uppercase text-[10px] tracking-widest hover:bg-cyan-400 transition-all">Créer</button>
              </form>
            </div>
            <div className="bg-black/20 rounded-3xl p-6 border border-white/5 min-h-[300px]">
              {renderTree(null)}
            </div>
          </div>
        )}

        {activeTab === 'cloud' && (
          <div className="max-w-lg mx-auto py-10">
            <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter mb-8 text-center">Connexion Cloud</h3>
            <form onSubmit={handleCloudSave} className="space-y-6">
              <input type="text" placeholder="ID Dossier Google Drive" value={cloudConfig.driveFolderId} onChange={e => setCloudConfig({...cloudConfig, driveFolderId: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:border-cyan-400 outline-none" />
              <div className="relative">
                <input type={showApiKey ? "text" : "password"} placeholder="API Key" value={cloudConfig.apiKey} onChange={e => setCloudConfig({...cloudConfig, apiKey: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:border-cyan-400 outline-none" />
                <button type="button" onClick={() => setShowApiKey(!showApiKey)} className="absolute right-6 top-1/2 -translate-y-1/2 text-white/20 hover:text-cyan-400">
                  {showApiKey ? 'O' : 'X'}
                </button>
              </div>
              <button type="submit" className="w-full bg-white text-slate-950 font-black py-5 rounded-2xl uppercase tracking-widest hover:bg-cyan-400 transition-all">Enregistrer</button>
            </form>
          </div>
        )}

        {activeTab === 'logs' && (
          <div className="space-y-4 max-h-[400px] overflow-y-auto no-scrollbar">
            {logs.map(log => (
              <div key={log.id} className="bg-white/[0.02] p-4 rounded-xl border border-white/5 flex gap-4 text-[11px] font-mono">
                <span className="text-white/20">[{log.timestamp}]</span>
                <span className="text-cyan-400 font-bold uppercase">{log.action}</span>
                <span className="text-white/60">{log.details}</span>
              </div>
            ))}
          </div>
        )}
      </div>

      {showDocModal.show && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-6 bg-black/90 backdrop-blur-xl">
          <form onSubmit={handlePublishDocument} className="bg-slate-900 border border-white/10 rounded-[3rem] p-10 max-w-lg w-full">
            <h4 className="text-2xl font-black text-white uppercase italic tracking-tighter mb-8 text-center">Ajouter un document</h4>
            <div className="space-y-4">
              <input required placeholder="Titre" value={newDoc.title} onChange={e => setNewDoc({...newDoc, title: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white outline-none" />
              <input placeholder="Description" value={newDoc.description} onChange={e => setNewDoc({...newDoc, description: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white outline-none" />
              <input required placeholder="URL du fichier (Google Drive Link)" value={newDoc.url} onChange={e => setNewDoc({...newDoc, url: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-cyan-400 font-mono outline-none" />
            </div>
            <div className="flex gap-4 mt-8">
              <button type="button" onClick={() => setShowDocModal({show: false, catId: ''})} className="flex-1 bg-white/5 text-white/40 font-black py-4 rounded-2xl uppercase text-[10px]">Annuler</button>
              <button type="submit" className="flex-1 bg-cyan-500 text-slate-900 font-black py-4 rounded-2xl uppercase text-[10px]">Publier</button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import AuroraBackground from './components/AuroraBackground.tsx';
import DocumentCard from './components/DocumentCard.tsx';
import AdminDashboard from './components/AdminDashboard.tsx';
import { storageService } from './services/storageService.ts';
import { Category, Document } from './types.ts';

const App: React.FC = () => {
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [navigationPath, setNavigationPath] = useState<Category[]>([]);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminUsername, setAdminUsername] = useState('');
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState(false);

  const refreshData = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
  };

  useEffect(() => {
    refreshData();
    // Tracking de visite simple pour la v4.0
    storageService.updateStats(1, 0);
  }, []);

  const navigateTo = (cat: Category | null) => {
    if (!cat) {
      setNavigationPath([]);
    } else {
      setNavigationPath([...navigationPath, cat]);
    }
  };

  const goBackTo = (index: number | null) => {
    if (index === null) setNavigationPath([]);
    else setNavigationPath(navigationPath.slice(0, index + 1));
  };

  const currentLevelCategories = useMemo(() => {
    const parentId = navigationPath.length > 0 ? navigationPath[navigationPath.length - 1].id : null;
    return searchQuery ? [] : categories.filter(c => c.parentId === parentId);
  }, [categories, navigationPath, searchQuery]);

  const currentLevelDocuments = useMemo(() => {
    if (searchQuery) {
      return documents.filter(d => 
        d.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        d.description.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }
    if (navigationPath.length === 0) return [];
    const lastCatId = navigationPath[navigationPath.length - 1].id;
    return documents.filter(doc => doc.categoryId === lastCatId);
  }, [documents, navigationPath, searchQuery]);

  const handleDownload = (doc: Document) => {
    if (doc.fileUrl && doc.fileUrl !== '#') {
      window.open(doc.fileUrl, '_blank');
      storageService.incrementDownload(doc.id);
      refreshData();
    } else {
      alert("Lien non disponible.");
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminUsername === 'Léon' && adminPassword === 'mazedxn7') {
      setIsAdminMode(true);
      setShowAdminLogin(false);
      setLoginError(false);
      storageService.addLog('AUTH', 'Connexion réussie à la console v4.0');
    } else {
      setLoginError(true);
    }
  };

  return (
    <div className="min-h-screen text-slate-100 selection:bg-cyan-500/30">
      <AuroraBackground />

      <header className="container mx-auto px-6 py-12 md:py-16 flex flex-col md:flex-row items-center justify-between gap-8">
        <div className="flex items-center gap-6 cursor-pointer group" onClick={() => navigateTo(null)}>
          <div className="w-14 h-14 bg-cyan-500 rounded-2xl flex items-center justify-center shadow-2xl group-hover:rotate-6 transition-all duration-300">
             <svg className="w-8 h-8 text-slate-950" fill="currentColor" viewBox="0 0 20 20"><path d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z" /></svg>
          </div>
          <div>
            <h1 className="text-3xl font-black tracking-tighter text-white uppercase">Success<span className="text-cyan-400">Polaris</span></h1>
            <p className="text-[9px] uppercase tracking-[0.4em] text-white/30 font-bold">Ressources Académiques v4.0</p>
          </div>
        </div>

        {!isAdminMode && (
          <div className="w-full max-w-md relative group">
            <input 
              type="text" 
              placeholder="Rechercher dans la bibliothèque..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-white/[0.02] border border-white/10 rounded-2xl pl-12 pr-6 py-4 text-sm focus:border-cyan-400/50 outline-none backdrop-blur-md transition-all"
            />
            <svg className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-white/20 group-focus-within:text-cyan-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </div>
        )}
      </header>

      <main className="container mx-auto px-6 pb-32">
        {isAdminMode ? (
          <div className="animate-in">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-xl font-bold uppercase tracking-widest text-white/50">Dashboard Administrateur</h2>
              <button 
                onClick={() => setIsAdminMode(false)}
                className="bg-white/5 hover:bg-white/10 text-white px-6 py-2 rounded-xl text-[10px] font-black uppercase transition-all border border-white/10"
              >Déconnexion</button>
            </div>
            <AdminDashboard />
          </div>
        ) : (
          <div className="space-y-10">
            {/* Navigation Navigation */}
            <div className="flex items-center gap-2 overflow-x-auto no-scrollbar py-2">
              <button 
                onClick={() => goBackTo(null)}
                className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${navigationPath.length === 0 ? 'bg-cyan-500 text-slate-900' : 'bg-white/5 text-white/40 hover:text-white'}`}
              >Accueil</button>
              {navigationPath.map((cat, i) => (
                <React.Fragment key={cat.id}>
                  <span className="text-white/10">/</span>
                  <button 
                    onClick={() => goBackTo(i)}
                    className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${i === navigationPath.length - 1 ? 'bg-cyan-500 text-slate-900' : 'bg-white/5 text-white/40 hover:text-white'}`}
                  >{cat.name}</button>
                </React.Fragment>
              ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
              {/* Sidebar Catégories */}
              {!searchQuery && (
                <div className="lg:col-span-4 space-y-3">
                  {currentLevelCategories.map(cat => (
                    <button 
                      key={cat.id}
                      onClick={() => navigateTo(cat)}
                      className="w-full flex items-center justify-between p-5 bg-slate-900/40 border border-white/5 hover:border-cyan-500/20 rounded-2xl group transition-all text-left"
                    >
                      <span className="text-base font-semibold text-white/60 group-hover:text-white">{cat.name}</span>
                      <svg className="w-4 h-4 text-white/10 group-hover:text-cyan-400 transition-all" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                    </button>
                  ))}
                  {currentLevelCategories.length === 0 && navigationPath.length > 0 && (
                    <div className="p-8 text-center bg-white/[0.01] rounded-2xl border border-dashed border-white/5">
                      <p className="text-white/20 text-xs italic">Dossier final atteint.</p>
                    </div>
                  )}
                </div>
              )}

              {/* Contenu Principal */}
              <div className={`${searchQuery ? 'lg:col-span-12' : 'lg:col-span-8'} grid grid-cols-1 md:grid-cols-2 gap-6`}>
                {currentLevelDocuments.map(doc => (
                  <DocumentCard key={doc.id} doc={doc} onDownload={handleDownload} />
                ))}
                {currentLevelDocuments.length === 0 && (
                  <div className="col-span-full py-20 text-center">
                    <p className="text-white/10 italic text-sm">Aucune ressource disponible ici.</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="fixed bottom-0 left-0 w-full p-6 bg-slate-950/80 backdrop-blur-xl border-t border-white/5 flex flex-col md:flex-row items-center justify-between z-[100] gap-4">
        <p className="text-[10px] text-white/20 font-black uppercase tracking-[0.4em]">SuccessPolaris v4.0.1 Stable</p>
        <button 
          onClick={() => setShowAdminLogin(true)}
          className="text-[9px] text-white/20 hover:text-cyan-400 font-bold uppercase tracking-widest transition-colors"
        >Console Admin</button>
      </footer>

      {showAdminLogin && (
        <div className="fixed inset-0 z-[3000] flex items-center justify-center p-6 bg-black/90 backdrop-blur-sm">
          <div className="max-w-sm w-full p-8 bg-slate-900 border border-white/10 rounded-3xl shadow-2xl relative">
            <button onClick={() => setShowAdminLogin(false)} className="absolute top-6 right-6 text-white/20 hover:text-white">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
            <h3 className="text-2xl font-black text-white uppercase italic mb-8 text-center tracking-tighter">Accès <span className="text-cyan-400">Restreint</span></h3>
            <form onSubmit={handleAdminLogin} className="space-y-4">
              <input type="text" placeholder="ID Léon" value={adminUsername} onChange={e => setAdminUsername(e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-xl px-5 py-3 text-white focus:border-cyan-400 outline-none text-sm" />
              <input type="password" placeholder="Clé de sécurité" value={adminPassword} onChange={e => setAdminPassword(e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-xl px-5 py-3 text-white focus:border-cyan-400 outline-none text-sm" />
              <button type="submit" className="w-full bg-cyan-500 text-slate-950 font-black py-4 rounded-xl uppercase text-[10px] tracking-widest hover:bg-cyan-400 transition-all shadow-lg">Identifier</button>
              {loginError && <p className="text-red-500 text-[10px] text-center uppercase font-bold mt-4 tracking-widest">Échec de connexion</p>}
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

