    refresh();
  };

  const renderTree = (parentId: string | null, level: number = 0) => {
    const children = categories.filter(c => c.parentId === parentId);
    return (
      <div className={`space-y-2 ${level > 0 ? 'ml-8 border-l border-white/5 pl-4 mt-2' : ''}`}>
        {children.map(cat => {
          const hasSubCats = categories.some(c => c.parentId === cat.id);
          const docCount = documents.filter(d => d.categoryId === cat.id).length;

          return (
            <div key={cat.id} className="group bg-white/[0.02] p-4 rounded-2xl border border-transparent hover:border-cyan-500/20 transition-all">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <span className="text-xl opacity-40 group-hover:opacity-100 transition-opacity">
                    {level === 0 ? '📂' : '📄'}
                  </span>
                  <div className="flex flex-col">
                    <span className="font-bold text-white/80">{cat.name}</span>
                    {docCount > 0 && <span className="text-[9px] text-cyan-400 uppercase font-black tracking-widest">{docCount} fichiers</span>}
                  </div>
                </div>
                <div className="flex items-center gap-1">
                  <button onClick={() => { const n = prompt(`Nouveau sous-dossier dans "${cat.name}" :`); if(n) { storageService.saveCategory(n, cat.id); refresh(); } }} className="p-2 hover:bg-cyan-500/10 rounded-lg text-white/20 hover:text-cyan-400">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                  </button>
                  {!hasSubCats && (
                    <button onClick={() => setShowDocModal({ show: true, catId: cat.id })} className="p-2 hover:bg-yellow-500/10 rounded-lg text-white/20 hover:text-yellow-400">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                    </button>
                  )}
                  <button onClick={() => { if(confirm("Supprimer cette catégorie ?")) { storageService.deleteCategory(cat.id); refresh(); } }} className="p-2 hover:bg-red-500/10 rounded-lg text-white/20 hover:text-red-400">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  </button>
                </div>
              </div>
              {renderTree(cat.id, level + 1)}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="bg-slate-900/80 rounded-[2.5rem] border border-white/5 overflow-hidden shadow-2xl backdrop-blur-3xl">
      <div className="flex bg-black/40 p-2 gap-2 border-b border-white/5">
        {(['tree', 'cloud', 'logs'] as const).map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
              activeTab === tab ? 'bg-cyan-500 text-slate-900 shadow-xl shadow-cyan-500/20' : 'text-white/40 hover:text-white hover:bg-white/5'
            }`}
          >
            {tab === 'tree' ? 'Structure' : tab === 'cloud' ? 'Configuration' : 'Journal'}
          </button>
        ))}
      </div>

      <div className="p-8 md:p-12">
        {activeTab === 'tree' && (
          <div className="space-y-10">
            <div className="flex justify-between items-center">
              <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">Organisation</h3>
              <form onSubmit={(e) => { e.preventDefault(); if(newRootName) { storageService.saveCategory(newRootName, null); setNewRootName(''); refresh(); } }} className="flex gap-2">
                <input type="text" placeholder="Nouveau niveau..." value={newRootName} onChange={(e) => setNewRootName(e.target.value)} className="bg-white/5 border border-white/10 px-6 py-3 rounded-xl text-white outline-none focus:border-cyan-400 transition-all text-sm" />
                <button type="submit" className="bg-cyan-500 text-slate-900 px-6 py-3 rounded-xl font-black uppercase text-[10px] tracking-widest hover:bg-cyan-400 transition-all">Créer</button>
              </form>
            </div>
            <div className="bg-black/20 rounded-3xl p-6 border border-white/5 min-h-[300px]">
              {renderTree(null)}
            </div>
          </div>
        )}

        {activeTab === 'cloud' && (
          <div className="max-w-lg mx-auto py-10">
            <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter mb-8 text-center">Connexion Cloud</h3>
            <form onSubmit={handleCloudSave} className="space-y-6">
              <input type="text" placeholder="ID Dossier Google Drive" value={cloudConfig.driveFolderId} onChange={e => setCloudConfig({...cloudConfig, driveFolderId: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:border-cyan-400 outline-none" />
              <div className="relative">
                <input type={showApiKey ? "text" : "password"} placeholder="API Key" value={cloudConfig.apiKey} onChange={e => setCloudConfig({...cloudConfig, apiKey: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:border-cyan-400 outline-none" />
                <button type="button" onClick={() => setShowApiKey(!showApiKey)} className="absolute right-6 top-1/2 -translate-y-1/2 text-white/20 hover:text-cyan-400">
                  {showApiKey ? 'O' : 'X'}
                </button>
              </div>
              <button type="submit" className="w-full bg-white text-slate-950 font-black py-5 rounded-2xl uppercase tracking-widest hover:bg-cyan-400 transition-all">Enregistrer</button>
            </form>
          </div>
        )}

        {activeTab === 'logs' && (
          <div className="space-y-4 max-h-[400px] overflow-y-auto no-scrollbar">
            {logs.map(log => (
              <div key={log.id} className="bg-white/[0.02] p-4 rounded-xl border border-white/5 flex gap-4 text-[11px] font-mono">
                <span className="text-white/20">[{log.timestamp}]</span>
                <span className="text-cyan-400 font-bold uppercase">{log.action}</span>
                <span className="text-white/60">{log.details}</span>
              </div>
            ))}
          </div>
        )}
      </div>

      {showDocModal.show && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-6 bg-black/90 backdrop-blur-xl">
          <form onSubmit={handlePublishDocument} className="bg-slate-900 border border-white/10 rounded-[3rem] p-10 max-w-lg w-full">
            <h4 className="text-2xl font-black text-white uppercase italic tracking-tighter mb-8 text-center">Ajouter un document</h4>
            <div className="space-y-4">
              <input required placeholder="Titre" value={newDoc.title} onChange={e => setNewDoc({...newDoc, title: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white outline-none" />
              <input placeholder="Description" value={newDoc.description} onChange={e => setNewDoc({...newDoc, description: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white outline-none" />
              <input required placeholder="URL du fichier (Google Drive Link)" value={newDoc.url} onChange={e => setNewDoc({...newDoc, url: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-cyan-400 font-mono outline-none" />
            </div>
            <div className="flex gap-4 mt-8">
              <button type="button" onClick={() => setShowDocModal({show: false, catId: ''})} className="flex-1 bg-white/5 text-white/40 font-black py-4 rounded-2xl uppercase text-[10px]">Annuler</button>
              <button type="submit" className="flex-1 bg-cyan-500 text-slate-900 font-black py-4 rounded-2xl uppercase text-[10px]">Publier</button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

