  const [navigationPath, setNavigationPath] = useState<Category[]>([]);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminUsername, setAdminUsername] = useState('');
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const refreshData = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
  };

  useEffect(() => {
    refreshData();
    storageService.updateStats(1, 0);
  }, []);

  const navigateTo = (cat: Category | null) => {
    if (!cat) {
      setNavigationPath([]);
    } else {
      setNavigationPath([...navigationPath, cat]);
    }
  };

  const goBackTo = (index: number | null) => {
    if (index === null) setNavigationPath([]);
    else setNavigationPath(navigationPath.slice(0, index + 1));
  };

  const currentLevelCategories = useMemo(() => {
    const parentId = navigationPath.length > 0 ? navigationPath[navigationPath.length - 1].id : null;
    return searchQuery ? [] : categories.filter(c => c.parentId === parentId);
  }, [categories, navigationPath, searchQuery]);

  const currentLevelDocuments = useMemo(() => {
    if (searchQuery) {
      return documents.filter(d => 
        d.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        d.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
        d.tags.some(t => t.toLowerCase().includes(searchQuery.toLowerCase()))
      );
    }
    if (navigationPath.length === 0) return [];
    const lastCatId = navigationPath[navigationPath.length - 1].id;
    return documents.filter(doc => doc.categoryId === lastCatId);
  }, [documents, navigationPath, searchQuery]);

  const handleDownload = (doc: Document) => {
    if (doc.fileUrl && doc.fileUrl !== '#') {
      setIsSyncing(true);
      // Sensation de "système interne" avec un délai de connexion au Node
      setTimeout(() => {
        window.open(doc.fileUrl, '_blank');
        storageService.incrementDownload(doc.id);
        setIsSyncing(false);
        refreshData();
      }, 1200);
    } else {
      alert("Erreur de liaison avec le Node Polaris Cloud.");
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminUsername === 'Léon' && adminPassword === 'mazedxn7') {
      setIsAdminMode(true);
      setShowAdminLogin(false);
      setLoginError(false);
      storageService.addLog('AUTH', 'Session Administrateur v5.0 Master Edition');
    } else {
      setLoginError(true);
    }
  };

  return (
    <div className="min-h-screen text-slate-100 selection:bg-cyan-500/30 font-['Inter'] relative overflow-hidden">
      <AuroraBackground />

      <header className="container mx-auto px-6 py-12 md:py-24 flex flex-col md:flex-row items-center justify-between gap-12 relative z-50">
        <div className="flex items-center gap-10 cursor-pointer group" onClick={() => navigateTo(null)}>
          <div className="relative">
            <div className="absolute inset-0 bg-cyan-400 blur-[40px] opacity-20 group-hover:opacity-60 transition-all duration-700"></div>
            <div className="w-20 h-20 bg-gradient-to-tr from-cyan-600 to-blue-900 rounded-[2.5rem] flex items-center justify-center shadow-[0_20px_50px_rgba(0,0,0,0.5)] border border-white/10 relative z-10 group-hover:-rotate-12 transition-all duration-500">
               <svg className="w-10 h-10 text-cyan-100" fill="currentColor" viewBox="0 0 20 20"><path d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z" /></svg>
            </div>
          </div>
          <div>
            <h1 className="text-5xl font-black tracking-tighter text-white uppercase italic leading-none">Success<span className="text-cyan-400">Polaris</span></h1>
            <div className="flex items-center gap-4 mt-3">
              <span className="h-[2px] w-12 bg-cyan-500 shadow-[0_0_10px_#00d4ff]"></span>
              <p className="text-[11px] uppercase tracking-[0.6em] text-cyan-400/60 font-black">Master System v5.0</p>
            </div>
          </div>
        </div>

        {!isAdminMode && (
          <div className="w-full max-w-xl relative group">
            <div className="absolute inset-0 bg-cyan-500/10 blur-3xl rounded-full opacity-0 group-focus-within:opacity-100 transition-opacity"></div>
            <input 
              type="text" 
              placeholder="Chercher une archive, un cours ou un sujet..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-slate-900/40 border border-white/5 rounded-3xl pl-16 pr-8 py-6 text-sm focus:border-cyan-400/40 outline-none backdrop-blur-3xl transition-all relative z-10 shadow-2xl"
            />
            <svg className="absolute left-6 top-1/2 -translate-y-1/2 w-7 h-7 text-white/10 group-focus-within:text-cyan-400 z-20 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </div>
        )}
      </header>

      <main className="container mx-auto px-6 pb-48 relative z-10">
        {isAdminMode ? (
