                className={`px-10 py-5 rounded-[1.5rem] text-[10px] font-black uppercase tracking-[0.3em] transition-all whitespace-nowrap ${navigationPath.length === 0 ? 'bg-cyan-500 text-slate-950 shadow-[0_15px_30px_rgba(0,212,255,0.3)]' : 'text-white/30 hover:text-white'}`}
              >Racine du Cloud</button>
              {navigationPath.map((cat, i) => (
                <React.Fragment key={cat.id}>
