                  >{cat.name}</button>
                </React.Fragment>
              ))}
            </nav>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-16">
              {!searchQuery && (
                <div className="lg:col-span-4 space-y-6">
                  <h3 className="text-white/10 text-[10px] font-black uppercase tracking-[0.6em] pl-4">Architecture</h3>
                  {currentLevelCategories.map(cat => (
                    <button 
                      key={cat.id}
                      onClick={() => navigateTo(cat)}
                      className="w-full flex items-center justify-between p-8 bg-white/[0.02] border border-white/5 hover:border-cyan-500/40 rounded-[2.5rem] group transition-all duration-500 hover:-translate-y-1"
                    >
                      <div className="flex items-center gap-8">
                        <span className="text-3xl filter grayscale group-hover:grayscale-0 transition-all duration-500">{cat.icon || '📦'}</span>
