                  {currentLevelCategories.length === 0 && navigationPath.length > 0 && (
                    <div className="p-16 text-center bg-cyan-500/[0.02] rounded-[3rem] border border-dashed border-cyan-500/10">
                      <p className="text-cyan-400/30 text-[10px] font-black uppercase tracking-widest">Fin de l'arborescence Node</p>
