           <div className="relative">
              <div className="w-24 h-24 border-[6px] border-cyan-500/10 border-t-cyan-500 rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                 <div className="w-3 h-3 bg-cyan-500 rounded-full animate-pulse"></div>
              </div>
           </div>
           <p className="text-cyan-400 text-[11px] font-black uppercase tracking-[0.8em] mt-10 animate-pulse">Synchronisation Node-Cloud...</p>
        </div>
      )}

      {showAdminLogin && (
        <div className="fixed inset-0 z-[5000] flex items-center justify-center p-6 bg-black/98 backdrop-blur-3xl">
          <div className="max-w-md w-full p-16 bg-slate-900 border border-white/10 rounded-[4rem] shadow-[0_50px_100px_rgba(0,0,0,0.8)] relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-transparent via-cyan-500 to-transparent"></div>
            <button onClick={() => setShowAdminLogin(false)} className="absolute top-10 right-10 text-white/20 hover:text-white scale-150 transition-all">
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
            <div className="text-center mb-16">
              <h3 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-4">Master Login</h3>
              <p className="text-white/20 text-[10px] font-black uppercase tracking-[0.5em]">Identité Polaris Requise</p>
            </div>
            <form onSubmit={handleAdminLogin} className="space-y-8">
              <div className="space-y-2">
                <label className="text-[10px] text-white/30 font-black uppercase tracking-widest ml-4">Identifiant Master</label>
                <input type="text" value={adminUsername} onChange={e => setAdminUsername(e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-3xl px-8 py-6 text-white focus:border-cyan-400 outline-none text-lg font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] text-white/30 font-black uppercase tracking-widest ml-4">Clé Polaris</label>
                <input type="password" value={adminPassword} onChange={e => setAdminPassword(e.target.value)} className="w-full bg-black/40 border border-white/5 rounded-3xl px-8 py-6 text-white focus:border-cyan-400 outline-none text-lg font-bold" />
              </div>
              <button type="submit" className="w-full bg-cyan-500 text-slate-950 font-black py-7 rounded-3xl uppercase tracking-[0.2em] hover:bg-white transition-all shadow-[0_20px_40px_rgba(0,212,255,0.2)]">Entrer dans le Node</button>
              {loginError && <p className="text-red-500 text-[10px] text-center uppercase font-black mt-8 tracking-widest animate-bounce">Erreur d'Identification Master</p>}
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

