                <textarea placeholder="Détails du document..." value={newDoc.description} onChange={e => setNewDoc({...newDoc, description: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-8 py-5 text-white outline-none focus:border-cyan-400 h-24" />
