                     <option value="pdf">Document PDF</option>
                     <option value="docx">Fichier Office</option>
                     <option value="archive">Archive (.zip)</option>
                   </select>
                </div>
                <div className="space-y-2">
                   <label className="text-[10px] text-white/30 font-black uppercase tracking-widest ml-4">ID Node Cloud</label>
                   <input required placeholder="Lien direct Polaris Cloud" value={newDoc.url} onChange={e => setNewDoc({...newDoc, url: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-8 py-5 text-cyan-400 font-mono outline-none focus:border-cyan-400" />
                </div>
