            </div>
            <div className="flex gap-6 mt-12">
              <button type="button" onClick={() => setShowDocModal({show: false, catId: ''})} className="flex-1 bg-white/5 text-white/30 font-black py-6 rounded-2xl uppercase tracking-widest hover:bg-white/10 transition-all">Annuler</button>
              <button type="submit" className="flex-1 bg-cyan-500 text-slate-950 font-black py-6 rounded-2xl uppercase tracking-widest hover:bg-white transition-all shadow-2xl">Publier sur le Node</button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

