import React, { useEffect, useRef } from 'react';

const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', resize);
    resize();

    // Initialisation des étoiles avec vecteurs de mouvement
    const stars = Array.from({ length: 200 }, () => {
      const size = Math.random() * 1.5;
      return {
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        size: size,
        opacity: Math.random(),
        // Vitesse de scintillement
        twinkleSpeed: Math.random() * 0.01 + 0.005,
        // Vitesse de déplacement (très lente pour l'aspect constellation)
        // Les plus grosses étoiles (plus "proches") bougent légèrement plus vite
        vx: (Math.random() - 0.5) * (0.05 + size * 0.02),
        vy: (Math.random() - 0.5) * (0.05 + size * 0.02)
      };
    });

    const draw = (time: number) => {
      // Fond bleu profond spatial
      ctx.fillStyle = '#0a192f';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Dessin et mise à jour des étoiles
      stars.forEach(star => {
        // 1. Mise à jour de l'opacité (Scintillement)
        star.opacity += star.twinkleSpeed;
        if (star.opacity > 1 || star.opacity < 0) star.twinkleSpeed *= -1;

        // 2. Mise à jour de la position (Mouvement)
        star.x += star.vx;
        star.y += star.vy;

        // 3. Gestion des bords (Wrapping infini)
        if (star.x < 0) star.x = canvas.width;
        if (star.x > canvas.width) star.x = 0;
        if (star.y < 0) star.y = canvas.height;
        if (star.y > canvas.height) star.y = 0;

        // Rendu de l'étoile
        ctx.globalAlpha = Math.max(0, star.opacity);
        ctx.fillStyle = '#e6f1ff';
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2);
        ctx.fill();
      });

      // Effet Aurora (Gradients radiaux mouvants)
      ctx.globalAlpha = 0.08;
      const gradient = ctx.createRadialGradient(
        canvas.width * 0.5 + Math.sin(time * 0.0005) * 150,
        canvas.height * 0.2 + Math.cos(time * 0.0003) * 50,
        0,
        canvas.width * 0.5,
        canvas.height * 0.2,
        canvas.width * 0.7
      );
      gradient.addColorStop(0, '#00d4ff');
      gradient.addColorStop(0.4, '#7b4dff');
      gradient.addColorStop(1, 'transparent');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.globalAlpha = 1;
      animationFrameId = requestAnimationFrame(draw);
    };

    animationFrameId = requestAnimationFrame(draw);
    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return <canvas ref={canvasRef} className="fixed inset-0 z-[-1]" />;
};

