    if (doc.fileUrl && doc.fileUrl !== '#') {
      setIsSyncing(true);
      setTimeout(() => {
        window.open(doc.fileUrl, '_blank');
        storageService.incrementDownload(doc.id);
        setIsSyncing(false);
        refreshData();
