import { Category, Document, Stats, ActivityLog, CloudConfig, VisitorActivity } from '../types.ts';
import { INITIAL_CATEGORIES, INITIAL_DOCUMENTS } from '../constants.ts';

const KEYS = {
  CATEGORIES: 'sp_categories',
  DOCUMENTS: 'sp_documents',
  STATS: 'sp_stats',
  LOGS: 'sp_logs',
  VISITOR_ACTIVITY: 'sp_visitor_spy_logs',
  CLOUD_CONFIG: 'sp_cloud_config'
};

export const storageService = {
  // Utilitaire pour convertir un lien Drive en lien direct Cloud
  optimizeDriveUrl: (url: string): string => {
    if (url.includes('drive.google.com')) {
      const match = url.match(/\/d\/(.+?)\/(view|edit|usp)/);
      if (match && match[1]) {
        return `https://drive.google.com/uc?export=download&id=${match[1]}`;
      }
    }
    return url;
  },

  getCloudConfig: (): CloudConfig => {
    const data = localStorage.getItem(KEYS.CLOUD_CONFIG);
    return data ? JSON.parse(data) : { driveFolderId: '', apiKey: '', isConnected: false, lastSync: '' };
  },
  saveCloudConfig: (config: CloudConfig) => {
    localStorage.setItem(KEYS.CLOUD_CONFIG, JSON.stringify(config));
    storageService.addLog('CONFIG', `Node Cloud synchronisé.`);
  },

  getCategories: (): Category[] => {
    const data = localStorage.getItem(KEYS.CATEGORIES);
    if (!data) {
      localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(INITIAL_CATEGORIES));
      return INITIAL_CATEGORIES;
    }
    return JSON.parse(data);
  },
  saveCategory: (name: string, parentId: string | null) => {
    const cats = storageService.getCategories();
    const newCat = { id: `cat-${Date.now()}`, name, parentId };
    const updated = [...cats, newCat];
    localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(updated));
    storageService.addLog('SYSTEM', `Section créée : ${name}`);
    return newCat;
  },
  deleteCategory: (id: string) => {
    const cats = storageService.getCategories().filter(c => c.id !== id);
    const remainingDocs = storageService.getDocuments().filter(d => d.categoryId !== id);
    localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(cats));
    localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(remainingDocs));
  },

  getDocuments: (): Document[] => {
    const data = localStorage.getItem(KEYS.DOCUMENTS);
    if (!data) {
      localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(INITIAL_DOCUMENTS));
      return INITIAL_DOCUMENTS;
    }
    return JSON.parse(data);
  },
  saveDocuments: (docs: Document[]) => {
    localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(docs));
  },
  addDocument: async (docData: Omit<Document, 'id' | 'downloads' | 'dateAdded'>) => {
    const docs = storageService.getDocuments();
    // Optimisation du lien avant stockage
    const optimizedUrl = storageService.optimizeDriveUrl(docData.fileUrl);

    const newDoc: Document = {
      ...docData,
      fileUrl: optimizedUrl,
      id: `doc-${Date.now()}`,
      downloads: 0,
      dateAdded: new Date().toISOString()
    };
    storageService.saveDocuments([newDoc, ...docs]);
    storageService.addLog('UPLOAD', `Archive indexée : ${docData.title}`);
  },

  getVisitorActivities: (): VisitorActivity[] => {
    const data = localStorage.getItem(KEYS.VISITOR_ACTIVITY);
    return data ? JSON.parse(data) : [];
  },
  logVisit: () => {
    const activities = storageService.getVisitorActivities();
    const newVisit: VisitorActivity = {
      id: `v-${Date.now()}`,
      type: 'VISIT',
      timestamp: new Date().toLocaleString('fr-FR')
    };
    localStorage.setItem(KEYS.VISITOR_ACTIVITY, JSON.stringify([newVisit, ...activities].slice(0, 1000)));
    storageService.updateStats(1, 0);
  },
  logDownload: (email: string, fileName: string) => {
    const activities = storageService.getVisitorActivities();
    const newDownload: VisitorActivity = {
      id: `d-${Date.now()}`,
      type: 'DOWNLOAD',
      email,
      fileName,
      timestamp: new Date().toLocaleString('fr-FR')
    };
    localStorage.setItem(KEYS.VISITOR_ACTIVITY, JSON.stringify([newDownload, ...activities].slice(0, 1000)));
    storageService.updateStats(0, 1);
    storageService.addLog('TRAÇAGE', `Download par ${email} : ${fileName}`);
  },

  incrementDownload: (id: string) => {
    const docs = storageService.getDocuments();
    const docIndex = docs.findIndex(d => d.id === id);
    if (docIndex > -1) {
      docs[docIndex].downloads += 1;
      storageService.saveDocuments(docs);
    }
  },

  getStats: (): Stats => {
    const data = localStorage.getItem(KEYS.STATS);
    return data ? JSON.parse(data) : { totalVisits: 0, totalDownloads: 0 };
  },
  updateStats: (v: number, d: number) => {
    const s = storageService.getStats();
    localStorage.setItem(KEYS.STATS, JSON.stringify({ totalVisits: (s.totalVisits || 0) + v, totalDownloads: (s.totalDownloads || 0) + d }));
  },
  getLogs: (): ActivityLog[] => {
    const data = localStorage.getItem(KEYS.LOGS);
    return data ? JSON.parse(data) : [];
  },
  addLog: (action: any, details: string) => {
    const logs = storageService.getLogs();
    const newLog = { id: Date.now().toString(), action, details, timestamp: new Date().toLocaleString('fr-FR') };
    localStorage.setItem(KEYS.LOGS, JSON.stringify([newLog, ...logs].slice(0, 200)));
  }
};

