            </div>
          </div>
          <div>
            <h1 className="text-xl md:text-2xl font-black tracking-tighter text-white uppercase italic leading-none">Success<span className="text-cyan-400">Polaris</span></h1>
            <p className="text-[7px] uppercase tracking-[0.4em] text-cyan-400/30 font-black mt-1">Cloud Node v5.3</p>
          </div>
        </div>

        {!isAdminMode && (
