};

export default App;

import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService.ts';
import { Category, Document, VisitorActivity, CloudConfig } from '../types.ts';

const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'tree' | 'spy' | 'cloud' | 'logs'>('tree');
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [activities, setActivities] = useState<VisitorActivity[]>([]);
  const [cloudConfig, setCloudConfig] = useState<CloudConfig>(storageService.getCloudConfig());

  const [newRootName, setNewRootName] = useState('');
  const [showDocModal, setShowDocModal] = useState<{show: boolean, catId: string}>({ show: false, catId: '' });
  const [newDoc, setNewDoc] = useState({ title: '', description: '', url: '', type: 'pdf' as any });

  const refresh = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
    setActivities(storageService.getVisitorActivities());
    setCloudConfig(storageService.getCloudConfig());
  };

  useEffect(() => {
    refresh();
    const timer = setInterval(refresh, 8000); 
    return () => clearInterval(timer);
  }, []);

  const handleCloudSave = (e: React.FormEvent) => {
    e.preventDefault();
    storageService.saveCloudConfig({ ...cloudConfig, isConnected: true, lastSync: new Date().toISOString() });
    refresh();
    alert("Node Sync Configuration Active.");
  };

  const handlePublishDocument = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDoc.title || !newDoc.url) return;
    await storageService.addDocument({
      title: newDoc.title,
      description: newDoc.description,
      categoryId: showDocModal.catId,
      fileUrl: newDoc.url,
      fileType: newDoc.type,
      tags: [],
      size: newDoc.url.includes('drive.google.com') ? 'Polaris Cloud' : 'Direct Link'
    });
    setNewDoc({ title: '', description: '', url: '', type: 'pdf' });
    setShowDocModal({ show: false, catId: '' });
    refresh();
  };

  const renderTree = (parentId: string | null, level: number = 0) => {
    const children = categories.filter(c => c.parentId === parentId);
    return (
      <div className={`space-y-2 ${level > 0 ? 'ml-6 border-l border-white/5 pl-4 mt-2' : ''}`}>
        {children.map(cat => {
          const hasSubCats = categories.some(c => c.parentId === cat.id);
          const catDocs = documents.filter(d => d.categoryId === cat.id);
          return (
            <div key={cat.id} className="bg-white/[0.01] p-3 rounded-lg border border-white/5">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                   <span className="text-white/40 text-[9px] font-black">{catDocs.length > 0 ? `(${catDocs.length})` : ''}</span>
                   <span className="font-bold text-white/80 text-[10px] uppercase tracking-tighter">{cat.name}</span>
                </div>
                <div className="flex gap-1">
                  <button onClick={() => { const n = prompt(`Sous-catégorie :`); if(n) { storageService.saveCategory(n, cat.id); refresh(); } }} className="w-7 h-7 flex items-center justify-center bg-white/5 rounded text-white/10 hover:text-cyan-400 transition-colors">+</button>
                  {!hasSubCats && (
                    <button onClick={() => setShowDocModal({ show: true, catId: cat.id })} className="w-7 h-7 flex items-center justify-center bg-white/5 rounded text-white/10 hover:text-yellow-400 transition-colors">📄</button>
                  )}
                  <button onClick={() => { if(confirm("Supprimer cette section ?")) { storageService.deleteCategory(cat.id); refresh(); } }} className="w-7 h-7 flex items-center justify-center bg-white/5 rounded text-white/10 hover:text-red-400 transition-colors">×</button>
                </div>
              </div>
              {renderTree(cat.id, level + 1)}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="bg-slate-900/40 rounded-2xl border border-white/5 overflow-hidden backdrop-blur-3xl animate-in">
      <div className="flex bg-black/40 overflow-x-auto no-scrollbar border-b border-white/5">
        {(['tree', 'spy', 'cloud', 'logs'] as const).map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 py-3 px-4 text-[7px] font-black uppercase tracking-widest transition-all min-w-[90px] ${
              activeTab === tab ? 'bg-cyan-500 text-slate-950 shadow-[inset_0_0_15px_rgba(255,255,255,0.2)]' : 'text-white/20 hover:text-white hover:bg-white/5'
            }`}
          >
            {tab === 'tree' ? 'Node Tree' : tab === 'spy' ? "L'Espion" : tab === 'cloud' ? 'Cloud Sync' : 'Index Flux'}
          </button>
        ))}
      </div>

      <div className="p-4 md:p-8">
        {activeTab === 'tree' && (
          <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-center bg-white/5 p-4 rounded-xl border border-white/5 gap-3">
              <h3 className="text-[9px] font-black text-white/40 uppercase tracking-widest">Nouveau Node Racine</h3>
              <form onSubmit={(e) => { e.preventDefault(); if(newRootName) { storageService.saveCategory(newRootName, null); setNewRootName(''); refresh(); } }} className="flex gap-2 w-full sm:w-auto">
                <input type="text" placeholder="Nom du Node..." value={newRootName} onChange={(e) => setNewRootName(e.target.value)} className="bg-black/60 border border-white/10 px-4 py-1.5 rounded-lg text-[10px] outline-none focus:border-cyan-400 flex-1 sm:w-48" />
                <button type="submit" className="bg-white text-slate-950 px-4 py-1.5 rounded-lg font-black uppercase text-[7px] tracking-widest transition-all hover:bg-cyan-400">Créer</button>
              </form>
            </div>
            {renderTree(null)}
          </div>
        )}

        {activeTab === 'spy' && (
          <div className="space-y-6">
            <div className="grid grid-cols-3 gap-3">
               <div className="bg-white/5 p-4 rounded-xl border border-white/5 text-center">
                  <p className="text-[6px] text-white/20 uppercase font-black tracking-widest mb-1">Visites</p>
                  <p className="text-xl font-black text-white">{activities.filter(a => a.type === 'VISIT').length}</p>
               </div>
               <div className="bg-white/5 p-4 rounded-xl border border-white/5 text-center">
                  <p className="text-[6px] text-white/20 uppercase font-black tracking-widest mb-1">Flux Cloud</p>
                  <p className="text-xl font-black text-cyan-400">{activities.filter(a => a.type === 'DOWNLOAD').length}</p>
               </div>
               <div className="bg-white/5 p-4 rounded-xl border border-white/5 text-center">
                  <p className="text-[6px] text-white/20 uppercase font-black tracking-widest mb-1">Cibles</p>
                  <p className="text-xl font-black text-yellow-400">{new Set(activities.filter(a => a.email).map(a => a.email)).size}</p>
               </div>
            </div>

            <div className="overflow-x-auto no-scrollbar">
              <table className="w-full text-left">
                <thead>
                  <tr className="border-b border-white/5">
                    <th className="pb-3 text-[6px] font-black uppercase text-white/10 tracking-[0.2em]">Flux</th>
                    <th className="pb-3 text-[6px] font-black uppercase text-white/10 tracking-[0.2em]">Source / Cible</th>
