                        <span className={`px-1.5 py-0.5 rounded-[4px] text-[5px] font-black uppercase tracking-widest ${act.type === 'VISIT' ? 'bg-white/5 text-white/20' : 'bg-cyan-500/20 text-cyan-400'}`}>
