                <label className="text-[6px] text-white/20 font-black uppercase tracking-widest ml-1">Node Folder ID</label>
                <input type="text" placeholder="ID Dossier Cloud..." value={cloudConfig.driveFolderId} onChange={e => setCloudConfig({...cloudConfig, driveFolderId: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-lg px-4 py-2 text-[10px] text-white outline-none focus:border-cyan-400" />
              </div>
              <button type="submit" className="w-full bg-cyan-500 text-slate-950 font-black py-3 rounded-lg uppercase text-[7px] tracking-widest hover:bg-white transition-all shadow-lg shadow-cyan-500/5">Synchroniser le Node</button>
