              <textarea placeholder="Description Polaris..." value={newDoc.description} onChange={e => setNewDoc({...newDoc, description: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-lg px-4 py-2 text-[10px] text-white outline-none focus:border-cyan-400 h-16" />
