            </div>
            <div className="flex gap-3 mt-6">
              <button type="button" onClick={() => setShowDocModal({show: false, catId: ''})} className="flex-1 bg-white/5 text-white/20 font-black py-2 rounded-lg uppercase text-[7px] transition-all hover:bg-white/10">Retour</button>
              <button type="submit" className="flex-1 bg-cyan-500 text-slate-950 font-black py-2 rounded-lg uppercase text-[7px] transition-all hover:bg-white shadow-lg shadow-cyan-500/10">Publier</button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

