{
  "name": "SuccessPolaris",
  "version": "5.3.0",
  "description": "SuccessPolaris Master Edition - Système de Node Cloud Interne (Astarté Cloud-Sync) avec flux Google Drive Direct.",
  "requestFramePermissions": []
