import React, { useEffect, useRef } from 'react';

const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', resize);
    resize();

    // Système de particules stellaires
    const stars = Array.from({ length: 150 }, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      size: Math.random() * 1.5,
      opacity: Math.random(),
      twinkle: Math.random() * 0.02,
      speed: Math.random() * 0.05
    }));

    // Étoiles filantes
    const shootingStars: any[] = [];
    const createShootingStar = () => {
      shootingStars.push({
        x: Math.random() * canvas.width,
        y: Math.random() * (canvas.height / 2),
        len: Math.random() * 80 + 20,
        speed: Math.random() * 15 + 5,
        opacity: 1
      });
    };

    // Nébuleuses (Gradients mouvants)
    const nebulas = [
      { x: 0.2, y: 0.3, color: 'rgba(0, 212, 255, 0.1)', r: 0.5 },
      { x: 0.8, y: 0.7, color: 'rgba(123, 77, 255, 0.1)', r: 0.4 },
      { x: 0.5, y: 0.5, color: 'rgba(0, 100, 255, 0.05)', r: 0.6 }
    ];

    const draw = (time: number) => {
      ctx.fillStyle = '#050b18';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Dessin des nébuleuses
      nebulas.forEach((n, i) => {
        const moveX = Math.sin(time * 0.0002 + i) * 100;
        const moveY = Math.cos(time * 0.0001 + i) * 50;
        const grad = ctx.createRadialGradient(
          canvas.width * n.x + moveX, 
          canvas.height * n.y + moveY, 
          0, 
          canvas.width * n.x + moveX, 
          canvas.height * n.y + moveY, 
          canvas.width * n.r
        );
        grad.addColorStop(0, n.color);
        grad.addColorStop(1, 'transparent');
        ctx.fillStyle = grad;
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      });

      // Étoiles
      stars.forEach(s => {
        s.opacity += s.twinkle;
        if (s.opacity > 1 || s.opacity < 0.2) s.twinkle *= -1;
        s.y -= s.speed;
        if (s.y < 0) s.y = canvas.height;

        ctx.globalAlpha = s.opacity;
        ctx.fillStyle = '#e6f1ff';
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.size, 0, Math.PI * 2);
        ctx.fill();
      });

      // Étoiles filantes
      if (Math.random() < 0.005) createShootingStar();
      shootingStars.forEach((s, i) => {
        s.x -= s.speed;
        s.y += s.speed * 0.5;
        s.opacity -= 0.02;
        if (s.opacity <= 0) shootingStars.splice(i, 1);

        ctx.globalAlpha = s.opacity;
        ctx.strokeStyle = '#fff';
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(s.x, s.y);
        ctx.lineTo(s.x + s.len, s.y - s.len * 0.5);
        ctx.stroke();
      });

      ctx.globalAlpha = 1;
      animationFrameId = requestAnimationFrame(draw);
    };

    animationFrameId = requestAnimationFrame(draw);
    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return <canvas ref={canvasRef} className="fixed inset-0 z-[-1]" />;
};

export default AuroraBackground;

