import React, { useEffect, useRef } from 'react';

const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', resize);
    resize();

    const stars = Array.from({ length: 200 }, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      size: Math.random() * 2,
      opacity: Math.random(),
      twinkle: Math.random() * 0.03,
      speed: Math.random() * 0.08
    }));

    const nebulas = [
      { x: 0.1, y: 0.2, color: 'rgba(0, 212, 255, 0.15)', r: 0.6 },
      { x: 0.9, y: 0.8, color: 'rgba(123, 77, 255, 0.12)', r: 0.5 },
      { x: 0.5, y: 0.5, color: 'rgba(0, 100, 255, 0.08)', r: 0.7 }
    ];

    const draw = (time: number) => {
      ctx.fillStyle = '#020617';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      nebulas.forEach((n, i) => {
        const moveX = Math.sin(time * 0.0003 + i) * 150;
        const moveY = Math.cos(time * 0.0002 + i) * 80;
        const grad = ctx.createRadialGradient(
          canvas.width * n.x + moveX, 
          canvas.height * n.y + moveY, 
          0, 
          canvas.width * n.x + moveX, 
          canvas.height * n.y + moveY, 
          canvas.width * n.r
        );
        grad.addColorStop(0, n.color);
        grad.addColorStop(0.5, n.color.replace('0.1', '0.05'));
        grad.addColorStop(1, 'transparent');
        ctx.fillStyle = grad;
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      });

      stars.forEach(s => {
        s.opacity += s.twinkle;
        if (s.opacity > 1 || s.opacity < 0.2) s.twinkle *= -1;
        s.y -= s.speed;
        if (s.y < 0) s.y = canvas.height;

        ctx.globalAlpha = s.opacity;
        ctx.fillStyle = '#f8fafc';
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.size, 0, Math.PI * 2);
        ctx.fill();
      });

      if (Math.random() < 0.01) {
        ctx.strokeStyle = 'rgba(255,255,255,0.5)';
        ctx.lineWidth = 1;
        ctx.beginPath();
        const sx = Math.random() * canvas.width;
        const sy = Math.random() * canvas.height / 2;
        ctx.moveTo(sx, sy);
        ctx.lineTo(sx - 100, sy + 50);
        ctx.stroke();
      }

      ctx.globalAlpha = 1;
      animationFrameId = requestAnimationFrame(draw);
    };

    animationFrameId = requestAnimationFrame(draw);
    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return <canvas ref={canvasRef} className="fixed inset-0 z-[-1]" />;
};

export default AuroraBackground;

import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService.ts';
