const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'tree' | 'spy' | 'drive' | 'logs'>('tree');
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [activities, setActivities] = useState<VisitorActivity[]>([]);

  // Google Drive Flow 5.6
  const [isDriveOpen, setIsDriveOpen] = useState(false);
  const [importForm, setImportForm] = useState({
    title: '',
    url: '',
    categoryId: '',
    description: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);

  const refresh = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
    setActivities(storageService.getVisitorActivities());
  };

  useEffect(() => {
    refresh();
  }, []);

  const openOfficialDrive = () => {
    window.open('https://drive.google.com', '_blank');
    setIsDriveOpen(true);
  };

  const handleImportSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!importForm.url || !importForm.categoryId) return;

    setIsSubmitting(true);
    await storageService.addDocument({
      title: importForm.title || "Archive Sans Titre",
      description: importForm.description || "Aucune description fournie.",
      categoryId: importForm.categoryId,
      fileUrl: importForm.url,
      fileType: 'pdf',
      tags: ['Cloud'],
      size: 'Auto-Sync'
    });

    setTimeout(() => {
      setIsSubmitting(false);
      setImportForm({ title: '', url: '', categoryId: '', description: '' });
      refresh();
      alert("Document indexé avec succès dans le Node.");
