                          className="w-full bg-black/40 border border-white/10 rounded-xl px-5 py-3 text-[11px] text-white outline-none focus:border-cyan-400 transition-all h-[52px] resize-none"
                        />
                      </div>
                   </div>
                   <div className="lg:col-span-2 pt-4">
                      <button 
                        type="submit" 
                        disabled={isSubmitting}
                        className="w-full bg-cyan-500 text-slate-950 py-4 rounded-2xl text-[10px] font-black uppercase tracking-[0.3em] hover:bg-white transition-all shadow-xl shadow-cyan-500/10 disabled:opacity-50"
                      >
                        {isSubmitting ? 'Synchronisation du Flux...' : 'Valider l\'Indexation'}
                      </button>
                   </div>
                </form>
              </div>
            )}
          </div>
        )}

        {activeTab === 'logs' && (
          <div className="space-y-1 max-h-[450px] overflow-y-auto no-scrollbar pr-2 flex-1">
            {storageService.getLogs().map(log => (
              <div key={log.id} className="bg-white/[0.02] p-3 rounded-lg flex items-center text-[8px] font-mono hover:bg-white/[0.04] transition-all border border-transparent hover:border-white/5">
                   <span className="text-white/10 w-28 shrink-0">[{log.timestamp}]</span>
                   <span className="text-cyan-500/50 font-black w-24 shrink-0">{log.action}</span>
                   <span className="text-white/40 truncate">{log.details}</span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

