                            </div>
                          )}
                        </div>
                      </div>
                      <div className="space-y-2.5">
                        <label className="text-[8px] text-white/30 font-black uppercase tracking-[0.2em] ml-1">Description Polaris</label>
                        <textarea 
                          placeholder="Détails pour les étudiants..."
                          value={importForm.description}
                          onChange={e => setImportForm({...importForm, description: e.target.value})}
                          className="w-full bg-black/60 border border-white/10 rounded-2xl px-6 py-4 text-[12px] text-white outline-none focus:border-cyan-400 transition-all h-[62px] resize-none placeholder:text-white/10 italic"
                        />
                      </div>
                   </div>
                   <div className="lg:col-span-2 pt-6">
                      <button 
                        type="submit" 
                        disabled={isSubmitting}
                        className="w-full bg-cyan-500 text-slate-950 py-5 rounded-3xl text-[11px] font-black uppercase tracking-[0.4em] hover:bg-white transition-all shadow-2xl shadow-cyan-500/20 disabled:opacity-50 active:scale-[0.98]"
                      >
                        {isSubmitting ? 'Synchronisation du Node...' : 'Publier sur le Node'}
                      </button>
                   </div>
                </form>
              </div>
            )}
          </div>
        )}

        {activeTab === 'logs' && (
          <div className="space-y-2 max-h-[480px] overflow-y-auto no-scrollbar pr-4 flex-1 animate-in">
            {storageService.getLogs().map(log => (
              <div key={log.id} className="bg-white/[0.02] p-4 rounded-2xl flex items-center text-[9px] font-mono hover:bg-white/[0.04] transition-all border border-white/5">
