{
  "name": "SuccessPolaris",
  "version": "5.7.0",
  "description": "SuccessPolaris Master Edition - Système de Node Cloud (Nebula Deep-Import) avec Hiérarchie Dynamique et Pont Google Drive.",
  "requestFramePermissions": []
}

import { Category, Document, Stats, ActivityLog, CloudConfig, VisitorActivity } from '../types.ts';
import { INITIAL_CATEGORIES, INITIAL_DOCUMENTS } from '../constants.ts';

const KEYS = {
  CATEGORIES: 'sp_categories',
  DOCUMENTS: 'sp_documents',
  STATS: 'sp_stats',
  LOGS: 'sp_logs',
  VISITOR_ACTIVITY: 'sp_visitor_spy_logs',
  CLOUD_CONFIG: 'sp_cloud_config'
};

export const storageService = {
  optimizeDriveUrl: (url: string): string => {
    if (url.includes('drive.google.com')) {
      // Gère les différents formats de liens Drive (d/ID, open?id=ID, etc.)
      const idMatch = url.match(/\/d\/(.+?)\/|id=(.+?)(&|$)/);
      const id = idMatch ? (idMatch[1] || idMatch[2]) : null;
      if (id) {
        return `https://drive.google.com/uc?export=download&id=${id}`;
      }
    }
    return url;
  },

  getCategories: (): Category[] => {
    const data = localStorage.getItem(KEYS.CATEGORIES);
    if (!data) {
      localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(INITIAL_CATEGORIES));
      return INITIAL_CATEGORIES;
    }
    return JSON.parse(data);
  },

  saveCategory: (name: string, parentId: string | null): Category => {
    const cats = storageService.getCategories();
    const newCat = { 
      id: `cat-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`, 
      name: name.trim(), 
      parentId 
    };
    const updated = [...cats, newCat];
    localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(updated));
    storageService.addLog('SYSTEM', `Node créé : ${name}`);
    return newCat;
  },

  ensureCategoryPath: (path: string): string => {
    const parts = path.split('>').map(p => p.trim()).filter(p => p !== "");
    let currentParentId: string | null = null;
    let lastId = "";

    for (const part of parts) {
      // On récupère les catégories à chaque itération pour être sûr d'avoir les dernières créées
      const cats = storageService.getCategories();
      const existing = cats.find(c => 
        c.name.toLowerCase() === part.toLowerCase() && 
        c.parentId === currentParentId
      );

      if (existing) {
        currentParentId = existing.id;
        lastId = existing.id;
      } else {
        const newCat = storageService.saveCategory(part, currentParentId);
        currentParentId = newCat.id;
        lastId = newCat.id;
      }
    }
    return lastId;
  },

  deleteCategory: (id: string) => {
    const cats = storageService.getCategories().filter(c => c.id !== id);
    const remainingDocs = storageService.getDocuments().filter(d => d.categoryId !== id);
    localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(cats));
    localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(remainingDocs));
  },

  getDocuments: (): Document[] => {
    const data = localStorage.getItem(KEYS.DOCUMENTS);
    if (!data) {
      localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(INITIAL_DOCUMENTS));
      return INITIAL_DOCUMENTS;
    }
    return JSON.parse(data);
  },

  saveDocuments: (docs: Document[]) => {
    localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(docs));
  },

  addDocument: async (docData: Omit<Document, 'id' | 'downloads' | 'dateAdded'>) => {
    const docs = storageService.getDocuments();
    const optimizedUrl = storageService.optimizeDriveUrl(docData.fileUrl);

    const newDoc: Document = {
      ...docData,
      fileUrl: optimizedUrl,
      id: `doc-${Date.now()}`,
      downloads: 0,
      dateAdded: new Date().toISOString()
    };
    storageService.saveDocuments([newDoc, ...docs]);
    storageService.addLog('UPLOAD', `Archive publiée : ${docData.title}`);
  },

  getVisitorActivities: (): VisitorActivity[] => {
    const data = localStorage.getItem(KEYS.VISITOR_ACTIVITY);
    return data ? JSON.parse(data) : [];
  },

  logVisit: () => {
    const activities = storageService.getVisitorActivities();
    const newVisit: VisitorActivity = { id: `v-${Date.now()}`, type: 'VISIT', timestamp: new Date().toLocaleString('fr-FR') };
    localStorage.setItem(KEYS.VISITOR_ACTIVITY, JSON.stringify([newVisit, ...activities].slice(0, 500)));
    storageService.updateStats(1, 0);
  },

  logDownload: (email: string, fileName: string) => {
    const activities = storageService.getVisitorActivities();
    const newDownload: VisitorActivity = { id: `d-${Date.now()}`, type: 'DOWNLOAD', email, fileName, timestamp: new Date().toLocaleString('fr-FR') };
    localStorage.setItem(KEYS.VISITOR_ACTIVITY, JSON.stringify([newDownload, ...activities].slice(0, 500)));
    storageService.updateStats(0, 1);
  },

  incrementDownload: (id: string) => {
    const docs = storageService.getDocuments();
    const docIndex = docs.findIndex(d => d.id === id);
    if (docIndex > -1) {
      docs[docIndex].downloads += 1;
      storageService.saveDocuments(docs);
    }
  },

  getStats: (): Stats => {
    const data = localStorage.getItem(KEYS.STATS);
    return data ? JSON.parse(data) : { totalVisits: 0, totalDownloads: 0 };
  },

  updateStats: (v: number, d: number) => {
    const s = storageService.getStats();
    localStorage.setItem(KEYS.STATS, JSON.stringify({ totalVisits: (s.totalVisits || 0) + v, totalDownloads: (s.totalDownloads || 0) + d }));
  },

  getLogs: (): ActivityLog[] => {
    const data = localStorage.getItem(KEYS.LOGS);
    return data ? JSON.parse(data) : [];
  },

  addLog: (action: any, details: string) => {
    const logs = storageService.getLogs();
    const newLog = { id: Date.now().toString(), action, details, timestamp: new Date().toLocaleString('fr-FR') };
    localStorage.setItem(KEYS.LOGS, JSON.stringify([newLog, ...logs].slice(0, 100)));
  }
};

import React, { useEffect, useRef } from 'react';

const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', resize);
    resize();

    const particles: any[] = [];
    for(let i=0; i<100; i++) {
        particles.push({
            x: Math.random() * canvas.width,
            y: Math.random() * canvas.height,
            vx: (Math.random() - 0.5) * 0.2,
            vy: (Math.random() - 0.5) * 0.2,
            size: Math.random() * 2 + 1,
            color: Math.random() > 0.5 ? '#00d4ff' : '#7b4dff',
            opacity: Math.random()
        });
    }

    const nebulas = [
      { x: 0.2, y: 0.2, c1: 'rgba(0, 212, 255, 0.2)', c2: 'rgba(0, 0, 0, 0)', r: 600, speed: 0.0005 },
      { x: 0.8, y: 0.8, c1: 'rgba(123, 77, 255, 0.15)', c2: 'rgba(0, 0, 0, 0)', r: 500, speed: 0.0003 },
      { x: 0.5, y: 0.5, c1: 'rgba(0, 80, 255, 0.1)', c2: 'rgba(0, 0, 0, 0)', r: 800, speed: 0.0002 }
    ];

    const draw = (time: number) => {
      ctx.fillStyle = '#020617';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Fond nébulaire fluide
      nebulas.forEach((n, i) => {
        const ox = Math.sin(time * n.speed + i) * 100;
        const oy = Math.cos(time * n.speed * 0.8 + i) * 100;
        const grad = ctx.createRadialGradient(
          canvas.width * n.x + ox, canvas.height * n.y + oy, 0,
          canvas.width * n.x + ox, canvas.height * n.y + oy, n.r
        );
        grad.addColorStop(0, n.c1);
        grad.addColorStop(1, n.c2);
        ctx.fillStyle = grad;
        ctx.globalCompositeOperation = 'screen';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      });

      ctx.globalCompositeOperation = 'source-over';

      // Particules stellaires animées
      particles.forEach(p => {
        p.x += p.vx;
        p.y += p.vy;
        if(p.x < 0) p.x = canvas.width;
        if(p.x > canvas.width) p.x = 0;
        if(p.y < 0) p.y = canvas.height;
        if(p.y > canvas.height) p.y = 0;

        ctx.globalAlpha = p.opacity * (0.5 + Math.sin(time * 0.002) * 0.5);
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fill();
      });

      if (Math.random() < 0.005) {
        ctx.strokeStyle = 'rgba(255,255,255,0.4)';
        ctx.lineWidth = 1;
        const x = Math.random() * canvas.width;
        const y = Math.random() * canvas.height / 3;
        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.lineTo(x - 150, y + 80);
        ctx.stroke();
      }

      ctx.globalAlpha = 1;
      animationFrameId = requestAnimationFrame(draw);
    };

    animationFrameId = requestAnimationFrame(draw);
    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return <canvas ref={canvasRef} className="fixed inset-0 z-[-1]" />;
};

export default AuroraBackground;

