                </div>
              </div>
              {renderTree(cat.id, level + 1)}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="bg-slate-900/40 rounded-[2.5rem] border border-white/5 overflow-hidden backdrop-blur-3xl animate-in shadow-2xl flex flex-col min-h-[650px]">
