              activeTab === tab ? 'border-cyan-500 bg-cyan-500/5 text-white shadow-[inset_0_-2px_10px_rgba(6,182,212,0.1)]' : 'border-transparent text-white/20 hover:text-white'
            }`}
          >
            {tab === 'tree' ? 'Structure Secteurs' : tab === 'spy' ? "L'Espion" : tab === 'drive' ? 'Cloud Sync Bridge' : 'Flux Logs'}
          </button>
        ))}
      </div>

