import { Category, Document, Stats, ActivityLog, AdminAccount, VisitorActivity } from '../types.ts';
import { INITIAL_CATEGORIES, INITIAL_DOCUMENTS } from '../constants.ts';

const KEYS = {
  CATEGORIES: 'sp_categories',
  DOCUMENTS: 'sp_documents',
  STATS: 'sp_stats',
  LOGS: 'sp_logs',
  VISITOR_ACTIVITY: 'sp_visitor_spy_logs',
  ACCOUNTS: 'sp_admin_accounts'
};

export const storageService = {
  optimizeDriveUrl: (url: string): string => {
    if (url.includes('drive.google.com')) {
      const idMatch = url.match(/\/d\/([a-zA-Z0-9_-]+)/) || url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
      const id = idMatch ? idMatch[1] : null;
      if (id) {
        return `https://drive.google.com/uc?export=download&id=${id}`;
      }
    }
    return url;
  },

  // --- ACCOUNTS ---
  getAccounts: (): AdminAccount[] => {
    const data = localStorage.getItem(KEYS.ACCOUNTS);
    if (!data) {
      const master = [{ id: '1', username: 'Léon', role: 'MASTER', lastLogin: new Date().toLocaleString() }];
      localStorage.setItem(KEYS.ACCOUNTS, JSON.stringify(master));
      return master as AdminAccount[];
    }
    return JSON.parse(data);
  },

  addAccount: (username: string) => {
    const accounts = storageService.getAccounts();
    const newAcc: AdminAccount = {
      id: `acc-${Date.now()}`,
      username,
      role: 'EDITOR',
      lastLogin: 'Jamais'
    };
    localStorage.setItem(KEYS.ACCOUNTS, JSON.stringify([...accounts, newAcc]));
    storageService.addLog('ACCOUNT', `Nouveau compte créé : ${username}`);
  },

  deleteAccount: (id: string) => {
    const accounts = storageService.getAccounts().filter(a => a.id !== id);
    localStorage.setItem(KEYS.ACCOUNTS, JSON.stringify(accounts));
  },

  // --- CATEGORIES ---
  getCategories: (): Category[] => {
    const data = localStorage.getItem(KEYS.CATEGORIES);
    if (!data) {
      localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(INITIAL_CATEGORIES));
      return INITIAL_CATEGORIES;
    }
    return JSON.parse(data);
  },

  saveCategory: (name: string, parentId: string | null): Category => {
    const cats = storageService.getCategories();
    const newCat = { 
      id: `cat-${Date.now()}-${Math.floor(Math.random() * 1000000)}`, 
      name: name.trim(), 
      parentId 
    };
    localStorage.setItem(KEYS.CATEGORIES, JSON.stringify([...cats, newCat]));
    storageService.addLog('SYSTEM', `Node créé : ${name}`);
    return newCat;
  },

  ensureCategoryPath: (path: string): string => {
    const parts = path.split('>').map(p => p.trim()).filter(p => p !== "");
    let currentParentId: string | null = null;
    let lastId = "";

    for (const part of parts) {
      const cats = storageService.getCategories();
      const existing = cats.find(c => 
        c.name.toLowerCase() === part.toLowerCase() && 
        c.parentId === currentParentId
      );

      if (existing) {
        currentParentId = existing.id;
        lastId = existing.id;
      } else {
        const newCat = storageService.saveCategory(part, currentParentId);
        currentParentId = newCat.id;
        lastId = newCat.id;
      }
    }
    return lastId;
  },

  deleteCategory: (id: string) => {
    // Suppression récursive (simplifiée ici en filtrant tout ce qui a cet ID comme parent)
    const allCats = storageService.getCategories();
    const toDelete = new Set([id]);

    // On trouve tous les descendants
    let foundNew = true;
    while(foundNew) {
      foundNew = false;
      allCats.forEach(c => {
        if(c.parentId && toDelete.has(c.parentId) && !toDelete.has(c.id)) {
          toDelete.add(c.id);
          foundNew = true;
        }
      });
    }

    const filteredCats = allCats.filter(c => !toDelete.has(c.id));
    const filteredDocs = storageService.getDocuments().filter(d => !toDelete.has(d.categoryId));

    localStorage.setItem(KEYS.CATEGORIES, JSON.stringify(filteredCats));
    localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(filteredDocs));
    storageService.addLog('DELETE', `Suppression de ${toDelete.size} sections`);
  },

  // --- DOCUMENTS ---
  getDocuments: (): Document[] => {
    const data = localStorage.getItem(KEYS.DOCUMENTS);
    return data ? JSON.parse(data) : INITIAL_DOCUMENTS;
  },

  addDocument: async (docData: Omit<Document, 'id' | 'downloads' | 'dateAdded'>) => {
    const docs = storageService.getDocuments();
    const optimizedUrl = storageService.optimizeDriveUrl(docData.fileUrl);

    const newDoc: Document = {
      ...docData,
      fileUrl: optimizedUrl,
      id: `doc-${Date.now()}`,
      downloads: 0,
      dateAdded: new Date().toISOString()
    };
    localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify([newDoc, ...docs]));
    storageService.addLog('UPLOAD', `Publication Drive : ${docData.title}`);
  },

  incrementDownload: (id: string) => {
    const docs = storageService.getDocuments();
    const docIndex = docs.findIndex(d => d.id === id);
    if (docIndex > -1) {
      docs[docIndex].downloads += 1;
      localStorage.setItem(KEYS.DOCUMENTS, JSON.stringify(docs));
    }
  },

  // --- LOGS & STATS ---
  logVisit: () => {
    const data = localStorage.getItem(KEYS.STATS);
    const s = data ? JSON.parse(data) : { totalVisits: 0, totalDownloads: 0 };
    localStorage.setItem(KEYS.STATS, JSON.stringify({ ...s, totalVisits: (s.totalVisits || 0) + 1 }));
  },

  logDownload: (email: string, fileName: string) => {
    const activities = JSON.parse(localStorage.getItem(KEYS.VISITOR_ACTIVITY) || '[]');
    const newAct = { id: `d-${Date.now()}`, type: 'DOWNLOAD', email, fileName, timestamp: new Date().toLocaleString() };
    localStorage.setItem(KEYS.VISITOR_ACTIVITY, JSON.stringify([newAct, ...activities].slice(0, 500)));
  },

  getVisitorActivities: () => JSON.parse(localStorage.getItem(KEYS.VISITOR_ACTIVITY) || '[]'),
  getLogs: () => JSON.parse(localStorage.getItem(KEYS.LOGS) || '[]'),
  addLog: (action: any, details: string) => {
    const logs = storageService.getLogs();
    const newLog = { id: Date.now().toString(), action, details, timestamp: new Date().toLocaleString() };
    localStorage.setItem(KEYS.LOGS, JSON.stringify([newLog, ...logs].slice(0, 100)));
  }
};

import React, { useEffect, useRef } from 'react';

const AuroraBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', resize);
    resize();

    const stars: any[] = [];
    for(let i=0; i<180; i++) {
        stars.push({
            x: Math.random() * canvas.width,
            y: Math.random() * canvas.height,
            vx: (Math.random() - 0.5) * 0.05,
            vy: (Math.random() - 0.5) * 0.05,
            size: Math.random() * 1.5 + 0.5,
            color: Math.random() > 0.8 ? '#00d4ff' : '#ffffff',
            opacity: Math.random()
        });
    }

    const draw = (time: number) => {
      ctx.fillStyle = '#050b18';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Aurora Glows
      const grad = ctx.createRadialGradient(canvas.width*0.2, canvas.height*0.2, 0, canvas.width*0.2, canvas.height*0.2, canvas.width*0.5);
      grad.addColorStop(0, 'rgba(0, 212, 255, 0.05)');
      grad.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.fillStyle = grad;
      ctx.fillRect(0,0, canvas.width, canvas.height);

      const grad2 = ctx.createRadialGradient(canvas.width*0.8, canvas.height*0.8, 0, canvas.width*0.8, canvas.height*0.8, canvas.width*0.4);
      grad2.addColorStop(0, 'rgba(123, 77, 255, 0.05)');
      grad2.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.fillStyle = grad2;
      ctx.fillRect(0,0, canvas.width, canvas.height);

      // Constellations
      ctx.lineWidth = 0.5;
      for(let i=0; i<stars.length; i++) {
        const s1 = stars[i];
        for(let j=i+1; j<stars.length; j++) {
            const s2 = stars[j];
            const dist = Math.sqrt(Math.pow(s1.x - s2.x, 2) + Math.pow(s1.y - s2.y, 2));
            if(dist < 100) {
                ctx.strokeStyle = `rgba(0, 212, 255, ${0.1 * (1 - dist/100)})`;
                ctx.beginPath();
                ctx.moveTo(s1.x, s1.y);
                ctx.lineTo(s2.x, s2.y);
                ctx.stroke();
            }
        }
      }

      // Stars
      stars.forEach(s => {
        s.x += s.vx;
        s.y += s.vy;
        if(s.x < 0) s.x = canvas.width;
        if(s.x > canvas.width) s.x = 0;
        if(s.y < 0) s.y = canvas.height;
        if(s.y > canvas.height) s.y = 0;

        ctx.globalAlpha = s.opacity * (0.6 + Math.sin(time * 0.001 + s.x) * 0.4);
        ctx.fillStyle = s.color;
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.size, 0, Math.PI * 2);
        ctx.fill();
      });

      ctx.globalAlpha = 1;
      animationFrameId = requestAnimationFrame(draw);
    };

    animationFrameId = requestAnimationFrame(draw);
    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return <canvas ref={canvasRef} className="fixed inset-0 z-[-1]" />;
};

export default AuroraBackground;

import React, { useState, useEffect } from 'react';
import { storageService } from '../services/storageService.ts';
import { Category, Document, VisitorActivity, AdminAccount } from '../types.ts';

interface AdminDashboardProps {
  onRefresh?: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onRefresh }) => {
  const [activeTab, setActiveTab] = useState<'tree' | 'spy' | 'drive' | 'accounts' | 'logs'>('tree');
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [activities, setActivities] = useState<VisitorActivity[]>([]);
  const [accounts, setAccounts] = useState<AdminAccount[]>([]);

  const [importForm, setImportForm] = useState({ title: '', url: '', categoryPath: '', description: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [newAccountName, setNewAccountName] = useState('');

  const refreshAll = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
    setActivities(storageService.getVisitorActivities());
    setAccounts(storageService.getAccounts());
    if (onRefresh) onRefresh();
  };

  useEffect(() => {
    refreshAll();
  }, []);

  const handleDeepImport = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!importForm.url || !importForm.categoryPath || !importForm.title) {
      alert("Veuillez remplir les informations de publication.");
      return;
    }

    setIsSubmitting(true);
    try {
      const finalCategoryId = storageService.ensureCategoryPath(importForm.categoryPath);
      await storageService.addDocument({
        title: importForm.title,
        description: importForm.description || "Archive Polaris Cloud",
        categoryId: finalCategoryId,
        fileUrl: importForm.url,
        fileType: 'pdf',
        tags: ['Drive'],
        size: 'Auto-Sync'
      });
      setImportForm({ title: '', url: '', categoryPath: '', description: '' });
      refreshAll();
      alert("Publication Drive réussie !");
    } catch (err) {
      alert("Erreur de synchronisation.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const addAccount = (e: React.FormEvent) => {
    e.preventDefault();
    if(!newAccountName) return;
    storageService.addAccount(newAccountName);
    setNewAccountName('');
    refreshAll();
  };

  const renderTree = (parentId: string | null, level: number = 0) => {
    const children = categories.filter(c => c.parentId === parentId);
    return (
      <div className={`space-y-2 ${level > 0 ? 'ml-6 border-l border-white/5 pl-4 mt-2' : ''}`}>
        {children.map(cat => {
          const catDocs = documents.filter(d => d.categoryId === cat.id);
          return (
            <div key={cat.id} className="bg-white/[0.02] p-4 rounded-2xl border border-white/5 group hover:border-cyan-500/20 transition-all">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <div className={`w-2 h-2 rounded-full ${level === 0 ? 'bg-cyan-500' : level === 1 ? 'bg-blue-400' : 'bg-purple-400'} animate-pulse shadow-[0_0_10px_currentColor]`}></div>
                   <span className="font-black text-white/90 text-[10px] uppercase tracking-tighter">{cat.name}</span>
                   <span className="text-white/20 text-[7px] font-bold">({catDocs.length} DOCS)</span>
                </div>
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
                  <button 
                    onClick={() => { const n = prompt(`Ajouter sous-ensemble à "${cat.name}" :`); if(n) { storageService.saveCategory(n, cat.id); refreshAll(); } }}
                    className="w-8 h-8 flex items-center justify-center bg-cyan-500/10 text-cyan-400 rounded-lg text-xs hover:bg-cyan-500 hover:text-slate-950 transition-all"
                  >+</button>
                  <button 
                    onClick={() => { if(confirm(`Supprimer "${cat.name}" et TOUT son contenu récursivement ?`)) { storageService.deleteCategory(cat.id); refreshAll(); } }}
                    className="w-8 h-8 flex items-center justify-center bg-red-500/10 text-red-400 rounded-lg text-xs hover:bg-red-500 hover:text-white transition-all"
                  >×</button>
                </div>
              </div>
              {renderTree(cat.id, level + 1)}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="bg-slate-900/40 rounded-[2.5rem] border border-white/5 overflow-hidden backdrop-blur-3xl animate-in shadow-2xl flex flex-col min-h-[700px]">
      <div className="flex bg-black/40 overflow-x-auto no-scrollbar border-b border-white/5">
        {(['tree', 'spy', 'drive', 'accounts', 'logs'] as const).map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 py-5 px-6 text-[8px] font-black uppercase tracking-widest transition-all min-w-[120px] border-b-2 ${
              activeTab === tab ? 'border-cyan-500 bg-cyan-500/5 text-white' : 'border-transparent text-white/20 hover:text-white'
            }`}
          >
            {tab === 'tree' ? 'Arborescence' : tab === 'spy' ? 'Espion' : tab === 'drive' ? 'Drive Bridge' : tab === 'accounts' ? 'Comptes' : 'Logs'}
          </button>
        ))}
      </div>

      <div className="p-8 md:p-14 flex-1 flex flex-col">
        {activeTab === 'tree' && (
