                  <p className="text-[8px] text-white/20 uppercase font-black tracking-widest mt-1">Gérez vos catégories et sous-ensembles à l'infini</p>
               </div>
               <button 
                 onClick={() => { const n = prompt("Nom de la catégorie racine :"); if(n) { storageService.saveCategory(n, null); refreshAll(); } }}
                 className="bg-white text-slate-950 px-8 py-3 rounded-2xl text-[9px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all shadow-xl"
               >Nouvelle Racine</button>
            </div>
            <div className="max-h-[450px] overflow-y-auto no-scrollbar pr-4">
               {categories.length === 0 ? <p className="text-center py-20 text-white/10 uppercase font-black text-[10px]">Aucun secteur actif</p> : renderTree(null)}
            </div>
          </div>
        )}

        {activeTab === 'accounts' && (
          <div className="space-y-10 animate-in">
             <div className="bg-white/[0.02] p-8 rounded-[2.5rem] border border-white/5">
                <h3 className="text-xs font-black text-white uppercase tracking-widest mb-6 italic">Enrôler un Administrateur</h3>
                <form onSubmit={addAccount} className="flex gap-4">
                   <input 
                     type="text" 
                     placeholder="Nom d'utilisateur..." 
                     value={newAccountName}
                     onChange={e => setNewAccountName(e.target.value)}
                     className="flex-1 bg-black/40 border border-white/10 rounded-2xl px-6 py-4 text-[12px] text-white outline-none focus:border-cyan-400 transition-all font-bold"
                   />
                   <button type="submit" className="bg-cyan-500 text-slate-950 px-8 py-4 rounded-2xl text-[9px] font-black uppercase tracking-widest hover:bg-white transition-all">Créer Compte</button>
                </form>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-4 overflow-y-auto max-h-[300px] no-scrollbar">
                {accounts.map(acc => (
                  <div key={acc.id} className="bg-white/[0.01] p-5 rounded-2xl border border-white/5 flex items-center justify-between group">
                     <div className="flex items-center gap-4">
                        <div className="w-10 h-10 bg-white/5 rounded-full flex items-center justify-center font-black text-white/20 uppercase text-[10px]">{acc.username[0]}</div>
                        <div>
                           <p className="text-[11px] font-black text-white/90 uppercase tracking-tight">{acc.username}</p>
                           <p className="text-[7px] text-white/20 uppercase font-black tracking-widest">Rôle: {acc.role} — Dernier accès: {acc.lastLogin}</p>
                        </div>
                     </div>
                     {acc.role !== 'MASTER' && (
                       <button 
                        onClick={() => { if(confirm("Supprimer ce compte ?")) { storageService.deleteAccount(acc.id); refreshAll(); } }}
                        className="w-8 h-8 bg-red-500/10 text-red-500 rounded-xl opacity-0 group-hover:opacity-100 transition-all hover:bg-red-500 hover:text-white"
                       >×</button>
                     )}
                  </div>
                ))}
             </div>
          </div>
        )}

        {activeTab === 'drive' && (
          <div className="animate-in space-y-10">
            <div className="bg-slate-900/80 p-12 rounded-[3rem] border border-white/10 flex items-center justify-between gap-10">
               <div className="max-w-xl">
                 <h3 className="text-2xl font-black text-white uppercase italic tracking-tighter mb-4">Polaris Drive Portal</h3>
                 <p className="text-[11px] text-white/30 uppercase font-black leading-relaxed tracking-widest">
                   Unique canal de publication autorisé. Copiez le lien "Partager" de votre document Drive <br/>
                   et définissez le chemin d'indexation (ex: Terminale > Physique > Mécanique).
                 </p>
               </div>
               <button onClick={() => window.open('https://drive.google.com', '_blank')} className="bg-white text-slate-950 px-10 py-5 rounded-2xl text-[11px] font-black uppercase tracking-widest hover:bg-cyan-400 transition-all shadow-2xl shrink-0">Mon Cloud Drive</button>
            </div>

            <form onSubmit={handleDeepImport} className="grid grid-cols-1 lg:grid-cols-2 gap-10 bg-white/[0.02] p-10 md:p-14 rounded-[3rem] border border-white/5">
                <div className="space-y-6">
                    <input type="text" required placeholder="Chemin du Node (A > B > C)" value={importForm.categoryPath} onChange={e => setImportForm({...importForm, categoryPath: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl px-6 py-4 text-[12px] text-white outline-none focus:border-cyan-400 transition-all font-bold" />
                    <input type="text" required placeholder="Titre de l'Archive" value={importForm.title} onChange={e => setImportForm({...importForm, title: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl px-6 py-4 text-[12px] text-white outline-none focus:border-cyan-400 transition-all font-bold" />
                </div>
                <div className="space-y-6">
                    <input type="url" required placeholder="Lien Partageable Drive" value={importForm.url} onChange={e => setImportForm({...importForm, url: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl px-6 py-4 text-[11px] text-cyan-400 font-mono outline-none focus:border-cyan-400 transition-all" />
                    <textarea placeholder="Description facultative..." value={importForm.description} onChange={e => setImportForm({...importForm, description: e.target.value})} className="w-full bg-black/60 border border-white/10 rounded-2xl px-6 py-4 text-[12px] text-white outline-none focus:border-cyan-400 transition-all h-[62px] resize-none italic" />
                </div>
                <button type="submit" disabled={isSubmitting} className="lg:col-span-2 bg-cyan-500 text-slate-950 py-5 rounded-3xl text-[11px] font-black uppercase tracking-[0.4em] hover:bg-white transition-all shadow-2xl active:scale-95">{isSubmitting ? 'Publication...' : 'Synchroniser au Node'}</button>
            </form>
          </div>
        )}

        {/* Spy & Logs Tabs similar to before but with refreshAll call */}
        {activeTab === 'spy' && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-in">
             <div className="bg-white/[0.02] p-10 rounded-[2.5rem] border border-white/5 text-center">
                <p className="text-[8px] text-white/20 uppercase font-black tracking-widest mb-2">Signaux Visites</p>
                <p className="text-4xl font-black text-white italic">{activities.filter(a => a.type === 'VISIT').length}</p>
             </div>
             <div className="bg-white/[0.02] p-10 rounded-[2.5rem] border border-white/5 text-center">
                <p className="text-[8px] text-white/20 uppercase font-black tracking-widest mb-2">Flux Archives</p>
                <p className="text-4xl font-black text-cyan-400 italic">{activities.filter(a => a.type === 'DOWNLOAD').length}</p>
             </div>
             <div className="bg-white/[0.02] p-10 rounded-[2.5rem] border border-white/5 text-center">
                <p className="text-[8px] text-white/20 uppercase font-black tracking-widest mb-2">Cibles Ciblées</p>
                <p className="text-4xl font-black text-yellow-400 italic">{new Set(activities.filter(a => a.email).map(a => a.email)).size}</p>
             </div>
          </div>
        )}

        {activeTab === 'logs' && (
          <div className="space-y-2 max-h-[480px] overflow-y-auto no-scrollbar pr-4 flex-1 animate-in">
            {storageService.getLogs().map(log => (
              <div key={log.id} className="bg-white/[0.02] p-4 rounded-2xl flex items-center text-[9px] font-mono border border-white/5">
                   <span className="text-white/20 w-32 shrink-0">[{log.timestamp}]</span>
                   <span className={`font-black w-24 shrink-0 ${log.action === 'UPLOAD' ? 'text-cyan-400' : 'text-white/40'}`}>{log.action}</span>
                   <span className="text-white/60 truncate italic">"{log.details}"</span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

