import React, { useState, useEffect, useMemo } from 'react';
import AuroraBackground from './components/AuroraBackground.tsx';
import DocumentCard from './components/DocumentCard.tsx';
import AdminDashboard from './components/AdminDashboard.tsx';
import { storageService } from './services/storageService.ts';
import { Category, Document } from './types.ts';

const App: React.FC = () => {
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [navigationPath, setNavigationPath] = useState<Category[]>([]);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminUsername, setAdminUsername] = useState('');
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const [showEmailModal, setShowEmailModal] = useState(false);
  const [pendingDoc, setPendingDoc] = useState<Document | null>(null);
  const [userEmail, setUserEmail] = useState('');
  const [emailError, setEmailError] = useState('');

  const refreshData = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
  };

  useEffect(() => {
    refreshData();
    storageService.logVisit(); 
  }, []);

  useEffect(() => {
    if (!isAdminMode) refreshData();
  }, [isAdminMode]);

  const navigateTo = (cat: Category | null) => {
    if (!cat) setNavigationPath([]);
    else setNavigationPath([...navigationPath, cat]);
  };

  const goBackTo = (index: number | null) => {
    if (index === null) setNavigationPath([]);
    else setNavigationPath(navigationPath.slice(0, index + 1));
  };

  const currentLevelCategories = useMemo(() => {
    const parentId = navigationPath.length > 0 ? navigationPath[navigationPath.length - 1].id : null;
    return searchQuery ? [] : categories.filter(c => c.parentId === parentId);
  }, [categories, navigationPath, searchQuery]);

  const currentLevelDocuments = useMemo(() => {
    if (searchQuery) {
      return documents.filter(d => 
        d.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        d.description.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }
    if (navigationPath.length === 0) return [];
    const lastCatId = navigationPath[navigationPath.length - 1].id;
    return documents.filter(doc => doc.categoryId === lastCatId);
  }, [documents, navigationPath, searchQuery]);

  const initiateDownload = (doc: Document) => {
    setPendingDoc(doc);
    setShowEmailModal(true);
  };

  const handleIdentityConfirm = (e: React.FormEvent) => {
    e.preventDefault();
    if (!userEmail.includes('@')) {
      setEmailError('Format d\'email invalide');
      return;
    }
    if (pendingDoc) {
      setIsSyncing(true);
      storageService.logDownload(userEmail, pendingDoc.title);
      storageService.incrementDownload(pendingDoc.id);
      setTimeout(() => {
        window.open(pendingDoc.fileUrl, '_blank');
        setIsSyncing(false);
        setShowEmailModal(false);
        setUserEmail('');
        setEmailError('');
        refreshData();
      }, 1500);
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const accounts = storageService.getAccounts();
    const user = accounts.find(a => a.username === adminUsername);

    // Pour cet exemple, le mot de passe est partagé "mazedxn7" pour tout admin
    if (user && adminPassword === 'mazedxn7') {
      setIsAdminMode(true);
      setShowAdminLogin(false);
      setLoginError(false);
      setAdminUsername('');
      setAdminPassword('');
      storageService.addLog('AUTH', `Admin ${user.username} connecté`);
    } else {
      setLoginError(true);
    }
  };

  return (
    <div className="min-h-screen text-slate-100 selection:bg-cyan-500/30 font-['Inter'] relative overflow-x-hidden pb-16">
      <AuroraBackground />

      <header className="container mx-auto px-6 py-12 md:py-20 flex flex-col md:flex-row items-center justify-between gap-8 relative z-50 animate-in">
        <div className="flex items-center gap-8 cursor-pointer group" onClick={() => navigateTo(null)}>
          <div className="relative">
            {/* Constellation visual effect around logo */}
            <svg className="absolute -inset-10 w-32 h-32 opacity-20 group-hover:opacity-60 group-hover:scale-110 transition-all duration-1000" viewBox="0 0 100 100">
               <circle cx="50" cy="50" r="1" fill="cyan" />
               <circle cx="20" cy="30" r="1" fill="white" />
               <circle cx="80" cy="40" r="1" fill="white" />
               <circle cx="40" cy="80" r="1" fill="cyan" />
               <line x1="20" y1="30" x2="50" y2="50" stroke="cyan" strokeWidth="0.2" />
               <line x1="50" y1="50" x2="80" y2="40" stroke="cyan" strokeWidth="0.2" />
               <line x1="50" y1="50" x2="40" y2="80" stroke="cyan" strokeWidth="0.2" />
            </svg>
            <div className="w-16 h-16 bg-slate-900 border border-white/10 rounded-3xl flex items-center justify-center relative z-10 group-hover:scale-110 transition-all duration-500 shadow-[0_0_40px_rgba(0,212,255,0.1)]">
               <svg className="w-8 h-8 text-cyan-400" fill="currentColor" viewBox="0 0 20 20"><path d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z" /></svg>
            </div>
          </div>
          <div>
            <h1 className="text-3xl md:text-4xl font-black tracking-tighter text-white uppercase italic leading-none">Success<span className="text-cyan-400">Polaris</span></h1>
            <p className="text-[10px] uppercase tracking-[0.6em] text-cyan-400 font-black mt-3 opacity-60">Majestueuse Voie du Savoir</p>
          </div>
        </div>

        {!isAdminMode && (
          <div className="w-full max-w-sm relative group px-2">
            <input 
              type="text" 
              placeholder="Sonder les archives stellaires..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-slate-950/40 border border-white/10 rounded-3xl pl-14 pr-6 py-5 text-[12px] focus:border-cyan-400/60 outline-none backdrop-blur-3xl transition-all placeholder:text-white/20 text-white font-bold"
            />
            <svg className="absolute left-7 top-1/2 -translate-y-1/2 w-5 h-5 text-cyan-400 z-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </div>
        )}
      </header>

      <main className="container mx-auto px-6 md:px-12 relative z-10 animate-in">
        {isAdminMode ? (
          <div>
            <div className="flex justify-between items-center mb-12 border-b border-white/5 pb-10">
              <div className="flex items-center gap-5">
                 <div className="w-3 h-3 bg-cyan-400 rounded-full shadow-[0_0_20px_#00d4ff] animate-pulse"></div>
                 <h2 className="text-md font-black uppercase italic tracking-[0.3em] text-white">Palais de Maîtrise SuccessPolaris</h2>
              </div>
              <button 
