                    <div className="w-1 h-1 bg-cyan-400 rounded-full animate-ping"></div> Secteurs Polaris
                  </h3>
                  <div className="grid grid-cols-1 gap-3">
                    {currentLevelCategories.map(cat => (
                      <button 
