                        </div>
                        <svg className="w-5 h-5 text-white/5 group-hover:text-cyan-400 group-hover:translate-x-1 transition-all" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" /></svg>
                      </button>
                    ))}
                    {currentLevelCategories.length === 0 && navigationPath.length === 0 && (
                      <div className="text-center py-20 opacity-10 italic text-[11px] uppercase font-black tracking-widest">Initialisation du Node...</div>
                    )}
                  </div>
                </div>
              )}

              <div className={`${searchQuery ? 'lg:col-span-12' : 'lg:col-span-8'} space-y-8`}>
                <h3 className="text-white/20 text-[9px] font-black uppercase tracking-[0.6em] mb-6 flex items-center gap-3">
                   <div className="w-1 h-1 bg-white/40 rounded-full"></div> Archives de Lumière
                </h3>
                {currentLevelDocuments.length > 0 ? (
                  <div className={`grid grid-cols-1 ${searchQuery ? 'md:grid-cols-2 lg:grid-cols-3' : 'md:grid-cols-2'} gap-10`}>
                    {currentLevelDocuments.map(doc => (
                      <DocumentCard key={doc.id} doc={doc} onDownload={initiateDownload} />
                    ))}
                  </div>
                ) : (
                  <div className="flex flex-col items-center justify-center py-32 bg-slate-900/10 rounded-[4rem] border border-dashed border-white/5 relative overflow-hidden group">
                    <div className="text-7xl mb-8 opacity-10 group-hover:scale-110 transition-transform duration-1000">🔭</div>
                    <p className="text-white/20 text-[11px] font-black uppercase tracking-[1em]">Horizon vide</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="fixed bottom-0 left-0 w-full py-6 px-12 bg-slate-950/80 backdrop-blur-3xl border-t border-white/5 flex items-center justify-between z-[1000] shadow-[0_-15px_60px_rgba(0,0,0,0.6)]">
        <div className="flex items-center gap-5">
          <div className="w-2 h-2 bg-cyan-500 rounded-full animate-pulse shadow-[0_0_15px_#00d4ff]"></div>
          <p className="text-[8px] text-white/30 font-black uppercase tracking-[0.5em]">SuccessPolaris — Node Astral v6.0 — Nemesis Edition</p>
        </div>

        <div className="text-right">
          <p className="text-[8px] text-white/10 font-bold uppercase tracking-[0.4em] flex items-center gap-4">
            © 2025 SuccessPolaris —
            <span 
              onClick={() => setShowAdminLogin(true)}
              className="text-white/20 hover:text-cyan-400 cursor-pointer transition-all font-black uppercase tracking-[0.3em] relative group px-3 py-1"
            >
              Maître du Dôme
              <span className="absolute bottom-0 left-0 w-0 h-[2px] bg-cyan-400 group-hover:w-full transition-all duration-700"></span>
