              <button type="submit" className="w-full bg-cyan-500 hover:bg-white text-slate-950 font-black py-5 rounded-3xl uppercase text-[10px] tracking-[0.4em] transition-all shadow-2xl shadow-cyan-500/20">Déverrouiller le Savoir</button>
            </form>
          </div>
        </div>
      )}

      {/* Admin Login */}
      {showAdminLogin && (
        <div className="fixed inset-0 z-[5000] flex items-center justify-center p-4 bg-black/98 backdrop-blur-3xl animate-in">
          <div className="max-w-[340px] w-full p-14 bg-slate-900/40 border border-white/5 rounded-[3rem] relative">
            <button onClick={() => setShowAdminLogin(false)} className="absolute top-8 right-8 text-white/10 hover:text-white transition-all">×</button>
            <div className="text-center mb-12">
              <h3 className="text-sm font-black text-white uppercase italic tracking-[0.5em]">Portail des Maîtres</h3>
            </div>
            <form onSubmit={handleAdminLogin} className="space-y-6">
              <input type="text" placeholder="Utilisateur" value={adminUsername} onChange={e => setAdminUsername(e.target.value)} className="w-full bg-black/70 border border-white/10 rounded-3xl px-8 py-5 text-[12px] text-white outline-none focus:border-cyan-400 transition-all font-bold" />
              <input type="password" placeholder="Clé Stellaire" value={adminPassword} onChange={e => setAdminPassword(e.target.value)} className="w-full bg-black/70 border border-white/10 rounded-3xl px-8 py-5 text-[12px] text-white outline-none focus:border-cyan-400 transition-all font-bold" />
              <button type="submit" className="w-full bg-white text-slate-950 font-black py-5 rounded-3xl uppercase text-[10px] tracking-[0.5em] hover:bg-cyan-400 transition-all shadow-3xl">Ouvrir le Dôme</button>
              {loginError && <p className="text-red-500 text-[8px] text-center uppercase font-black tracking-widest mt-6 italic">Sceau Refusé</p>}
            </form>
          </div>
        </div>
      )}

      {isSyncing && (
        <div className="fixed inset-0 z-[10000] flex flex-col items-center justify-center bg-slate-950/98 backdrop-blur-3xl">
           <div className="w-16 h-16 border-4 border-cyan-500/10 border-t-cyan-500 rounded-full animate-spin"></div>
           <p className="text-cyan-400 text-[10px] font-black uppercase tracking-[1em] mt-12 animate-pulse">Liaison Astral au Node...</p>
        </div>
      )}
    </div>
  );
};

