                  >+</button>
                  <button 
                    title="Supprimer récursivement"
                    onClick={() => { if(confirm(`Attention : supprimer "${cat.name}" supprimera TOUS les sous-ensembles et documents associés. Continuer ?`)) { storageService.deleteCategory(cat.id); refreshAll(); } }}
