              activeTab === tab ? 'border-cyan-500 bg-cyan-500/5 text-white shadow-[inset_0_-10px_20px_rgba(6,182,212,0.05)]' : 'border-transparent text-white/30 hover:text-white'
            }`}
          >
            {tab === 'tree' ? 'Arborescence du Dôme' : tab === 'spy' ? "Statistiques" : tab === 'drive' ? 'Bridge Google Drive' : tab === 'accounts' ? 'Gestion Comptes' : 'Logs Système'}
          </button>
        ))}
      </div>

      <div className="p-8 md:p-14 flex-1 flex flex-col overflow-y-auto max-h-[700px] no-scrollbar">
        {activeTab === 'tree' && (
          <div className="space-y-10 animate-in">
