               <div>
                  <h3 className="text-sm font-black text-white uppercase italic tracking-widest">Maillage Structurel SuccessPolaris</h3>
                  <p className="text-[9px] text-white/40 uppercase font-bold tracking-widest mt-2">Déployez des niveaux de catégories infinis</p>
               </div>
               <button 
