                 className="bg-cyan-500 text-slate-950 px-10 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-white transition-all shadow-lg hover:scale-105 active:scale-95"
               >Nouvelle Section Racine</button>
            </div>
            <div className="space-y-4">
