export default App;

import React, { useState, useEffect, useMemo } from 'react';
import AuroraBackground from './components/AuroraBackground.tsx';
import DocumentCard from './components/DocumentCard.tsx';
import AdminDashboard from './components/AdminDashboard.tsx';
import { storageService } from './services/storageService.ts';
import { Category, Document } from './types.ts';

const App: React.FC = () => {
  const [categories, setCategories] = useState<Category[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [navigationPath, setNavigationPath] = useState<Category[]>([]);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminUsername, setAdminUsername] = useState('');
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const [showEmailModal, setShowEmailModal] = useState(false);
  const [pendingDoc, setPendingDoc] = useState<Document | null>(null);
  const [userEmail, setUserEmail] = useState('');
  const [emailError, setEmailError] = useState('');

  const refreshData = () => {
    setCategories(storageService.getCategories());
    setDocuments(storageService.getDocuments());
  };

  useEffect(() => {
    refreshData();
    storageService.logVisit(); 
  }, []);

  useEffect(() => {
    if (!isAdminMode) refreshData();
  }, [isAdminMode]);

  const navigateTo = (cat: Category | null) => {
    if (!cat) setNavigationPath([]);
    else setNavigationPath([...navigationPath, cat]);
  };

  const goBackTo = (index: number | null) => {
    if (index === null) setNavigationPath([]);
    else setNavigationPath(navigationPath.slice(0, index + 1));
  };

  const currentLevelCategories = useMemo(() => {
    const parentId = navigationPath.length > 0 ? navigationPath[navigationPath.length - 1].id : null;
    return searchQuery ? [] : categories.filter(c => c.parentId === parentId);
  }, [categories, navigationPath, searchQuery]);

  const currentLevelDocuments = useMemo(() => {
    if (searchQuery) {
      return documents.filter(d => 
        d.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        d.description.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }
    if (navigationPath.length === 0) return [];
    const lastCatId = navigationPath[navigationPath.length - 1].id;
    return documents.filter(doc => doc.categoryId === lastCatId);
  }, [documents, navigationPath, searchQuery]);

  const initiateDownload = (doc: Document) => {
    setPendingDoc(doc);
    setShowEmailModal(true);
  };

  const handleIdentityConfirm = (e: React.FormEvent) => {
    e.preventDefault();
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(userEmail)) {
      setEmailError('Format d\'email invalide');
      return;
    }
    if (pendingDoc) {
      setIsSyncing(true);
      storageService.logDownload(userEmail, pendingDoc.title);
      storageService.incrementDownload(pendingDoc.id);
      setTimeout(() => {
        window.open(pendingDoc.fileUrl, '_blank');
        setIsSyncing(false);
        setShowEmailModal(false);
        setUserEmail('');
        setEmailError('');
        refreshData();
      }, 1500);
    }
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const accounts = storageService.getAccounts();
    const user = accounts.find(a => a.username.toLowerCase() === adminUsername.toLowerCase());

    if (user && adminPassword === 'mazedxn7') {
      setIsAdminMode(true);
      setShowAdminLogin(false);
      setLoginError(false);
      setAdminUsername('');
      setAdminPassword('');
      storageService.addLog('AUTH', `Liaison établie par ${user.username}`);
    } else {
      setLoginError(true);
      setTimeout(() => setLoginError(false), 3000);
    }
  };

  return (
    <div className="min-h-screen text-slate-100 selection:bg-cyan-500/30 font-['Inter'] relative overflow-x-hidden pb-20">
      <AuroraBackground />

      <header className="container mx-auto px-4 md:px-8 py-10 md:py-20 flex flex-col md:flex-row items-center justify-between gap-8 md:gap-12 relative z-50 animate-in">
        <div className="flex items-center gap-6 md:gap-12 cursor-pointer group" onClick={() => navigateTo(null)}>
          <div className="relative">
            {/* Majestic Constellation Floating Frame */}
            <div className="absolute -inset-16 md:-inset-24 w-48 md:w-64 h-48 md:h-64 pointer-events-none opacity-40 group-hover:opacity-100 transition-all duration-1000 scale-125 group-hover:scale-150 animate-float">
                <svg viewBox="0 0 100 100" className="w-full h-full fill-none overflow-visible">
                    <defs>
                        <filter id="glow" x="-20%" y="-20%" width="140%" height="140%">
                            <feGaussianBlur stdDeviation="1.5" result="blur" />
                            <feComposite in="SourceGraphic" in2="blur" operator="over" />
                        </filter>
                    </defs>
                    <circle cx="50" cy="50" r="1.8" fill="cyan" filter="url(#glow)" className="animate-pulse" />
                    <circle cx="15" cy="15" r="1.2" fill="white" filter="url(#glow)" />
                    <circle cx="85" cy="20" r="1.2" fill="white" filter="url(#glow)" />
                    <circle cx="92" cy="75" r="1.5" fill="cyan" filter="url(#glow)" />
                    <circle cx="8" cy="82" r="1.2" fill="white" filter="url(#glow)" />
                    <circle cx="50" cy="5" r="1" fill="white" filter="url(#glow)" />
                    <circle cx="50" cy="95" r="1" fill="white" filter="url(#glow)" />

                    <g className="opacity-50" stroke="cyan" strokeWidth="0.25" strokeDasharray="3 2">
                        <path d="M15 15 L50 50 L85 20" />
                        <path d="M50 50 L92 75" />
                        <path d="M50 50 L8 82" />
                        <path d="M50 5 L50 95" />
                    </g>
                    <path d="M15 15 Q 50 0, 85 20 Q 100 50, 92 75 Q 50 100, 8 82 Q 0 50, 15 15" stroke="rgba(0, 212, 255, 0.2)" strokeWidth="0.15" fill="none" />
                </svg>
            </div>

            <div className="w-16 md:w-20 h-16 md:h-20 bg-slate-950/90 border border-white/10 rounded-[1.5rem] md:rounded-[2rem] flex items-center justify-center relative z-10 group-hover:scale-110 group-hover:border-cyan-500/50 transition-all duration-700 shadow-[0_0_60px_rgba(0,212,255,0.2)]">
               <svg className="w-8 md:w-10 h-8 md:h-10 text-cyan-400 group-hover:rotate-[360deg] transition-transform duration-1000" fill="currentColor" viewBox="0 0 20 20">
                  <path d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z" />
               </svg>
            </div>
          </div>
          <div className="relative">
            <h1 className="text-3xl md:text-5xl lg:text-6xl font-black tracking-tighter text-white uppercase italic leading-none drop-shadow-[0_0_20px_rgba(0,212,255,0.4)]">
              Success<span className="text-cyan-400">Polaris</span>
            </h1>
            <p className="text-[8px] md:text-[11px] uppercase font-black mt-3 md:mt-5 opacity-40 pl-1 group-hover:opacity-100 group-hover:tracking-[1em] md:group-hover:tracking-[1.2em] transition-all duration-1000 tracking-[0.6em] md:tracking-[1em] text-cyan-400">Majestueuse Voie du Savoir</p>
            <div className="absolute -inset-10 md:-inset-16 bg-cyan-500/5 blur-[50px] md:blur-[70px] -z-10 rounded-full animate-pulse-slow"></div>
          </div>
        </div>

        {!isAdminMode && (
          <div className="w-full max-w-sm relative group px-2">
            <div className="absolute -inset-1 bg-gradient-to-r from-cyan-500/20 to-indigo-500/20 rounded-[2rem] blur opacity-0 group-focus-within:opacity-100 transition-opacity duration-500"></div>
            <input 
              type="text" 
              placeholder="Sonder les archives stellaires..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-slate-950/70 border border-white/10 rounded-[1.8rem] md:rounded-[2.5rem] pl-16 md:pl-20 pr-8 md:pr-10 py-5 md:py-7 text-[12px] md:text-[14px] focus:border-cyan-400/60 outline-none backdrop-blur-3xl transition-all placeholder:text-white/20 text-white font-black relative z-10 shadow-2xl"
            />
            <svg className="absolute left-7 md:left-10 top-1/2 -translate-y-1/2 w-5 md:w-6 h-5 md:h-6 text-cyan-400 z-20 group-hover:scale-125 transition-transform duration-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
          </div>
        )}
      </header>

      <main className="container mx-auto px-4 md:px-12 relative z-10 animate-in">
        {isAdminMode ? (
          <div className="space-y-8 md:space-y-12">
            <div className="flex flex-col sm:flex-row justify-between items-center mb-8 md:mb-16 border-b border-white/10 pb-8 md:pb-12 gap-4">
              <div className="flex items-center gap-4 md:gap-8">
                 <div className="w-4 md:w-5 h-4 md:h-5 bg-cyan-400 rounded-full shadow-[0_0_35px_#00d4ff] animate-pulse"></div>
                 <h2 className="text-lg md:text-xl font-black uppercase italic tracking-[0.3em] md:tracking-[0.5em] text-white">Palais de Maîtrise</h2>
              </div>
              <button 
                onClick={() => setIsAdminMode(false)}
                className="bg-white/5 hover:bg-red-500/20 hover:text-red-400 text-white/40 px-8 md:px-12 py-3 md:py-5 rounded-[1.2rem] md:rounded-[1.5rem] text-[9px] md:text-[11px] font-black uppercase tracking-widest border border-white/10 transition-all shadow-2xl active:scale-95"
              >Quitter le Dôme</button>
            </div>
            <AdminDashboard onRefresh={refreshData} />
          </div>
        ) : (
          <div className="space-y-12 md:space-y-24">
            <nav className="flex items-center gap-3 md:gap-5 overflow-x-auto no-scrollbar py-4 md:py-6 px-6 md:px-10 bg-slate-950/70 rounded-[2.5rem] md:rounded-[3.5rem] border border-white/10 backdrop-blur-3xl shadow-2xl">
              <button 
                onClick={() => goBackTo(null)}
                className={`px-8 md:px-12 py-3 md:py-5 rounded-[1.2rem] md:rounded-[1.5rem] text-[10px] md:text-[12px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${navigationPath.length === 0 ? 'bg-cyan-400 text-slate-950 shadow-[0_0_40px_rgba(0,212,255,0.4)] scale-105' : 'text-white/20 hover:text-white'}`}
              >Racine Polaris</button>
              {navigationPath.map((cat, i) => (
                <React.Fragment key={cat.id}>
