                        <div className="w-10 h-10 md:w-14 md:h-14 bg-white/5 rounded-[1rem] md:rounded-[1.2rem] flex items-center justify-center group-hover:bg-cyan-500 group-hover:text-slate-950 transition-all duration-700 shadow-lg relative z-10">
