              <div className={`${searchQuery ? 'lg:col-span-12' : 'lg:col-span-8 xl:col-span-7'} space-y-8 md:space-y-12`}>
                <h3 className="text-white/20 text-[9px] md:text-[11px] font-black uppercase tracking-[0.8em] md:tracking-[1em] mb-6 md:mb-12 flex items-center gap-4 pl-3">
                   <div className="w-1.5 md:w-2 h-1.5 md:h-2 bg-indigo-500 rounded-full"></div> Archives du Node
                </h3>
                {currentLevelDocuments.length > 0 ? (
                  <div className={`grid grid-cols-1 ${searchQuery ? 'sm:grid-cols-2 lg:grid-cols-3' : 'sm:grid-cols-2'} gap-8 md:gap-14`}>
                    {currentLevelDocuments.map(doc => (
