                  <div className="flex flex-col items-center justify-center py-24 md:py-48 bg-slate-900/20 rounded-[4rem] md:rounded-[6rem] border border-dashed border-white/10 relative overflow-hidden group shadow-inner">
                    <div className="text-7xl md:text-9xl mb-8 md:mb-12 opacity-5 group-hover:opacity-20 group-hover:scale-110 transition-all duration-1000 grayscale group-hover:grayscale-0">🔭</div>
                    <p className="text-white/10 text-[12px] md:text-[14px] font-black uppercase tracking-[1.5em] md:tracking-[2em] animate-pulse-slow">Dimension Inexplorée</p>
                    <div className="absolute inset-0 bg-gradient-to-b from-transparent to-cyan-500/5 opacity-0 group-hover:opacity-100 transition-opacity duration-1000"></div>
                  </div>
