          </div>
        )}
      </main>

      <footer className="fixed bottom-0 left-0 w-full py-3 md:py-5 px-6 md:px-14 bg-slate-950/80 backdrop-blur-3xl border-t border-white/10 flex flex-col sm:flex-row items-center justify-between z-[1000] shadow-[0_-25px_100px_rgba(0,0,0,0.9)] gap-3 md:gap-6">
        <div className="flex items-center gap-4 md:gap-8">
