            <button onClick={() => { setShowEmailModal(false); setEmailError(''); setUserEmail(''); }} className="absolute top-10 right-10 text-white/20 hover:text-white transition-all text-3xl hover:rotate-90">×</button>
            <div className="text-center mb-10 md:mb-16">
              <h3 className="text-md font-black text-white uppercase italic tracking-[0.6em] mb-4">Sceau d'Identité</h3>
