                 <p className="text-[12px] md:text-[14px] text-cyan-400 font-black text-center italic tracking-tight line-clamp-2 leading-loose">{pendingDoc?.title}</p>
              </div>
              <div className="space-y-4 md:space-y-5">
                  <input type="email" required placeholder="votre@email.com" value={userEmail} onChange={e => setUserEmail(e.target.value)} className="w-full bg-black/70 border border-white/10 rounded-[1.5rem] md:rounded-[2rem] px-8 md:px-12 py-5 md:py-7 text-[14px] md:text-[16px] text-white focus:border-cyan-400 outline-none transition-all placeholder:text-white/5 font-black text-center" />
                  {emailError && <p className="text-red-500 text-[10px] md:text-[11px] font-black uppercase tracking-widest pt-3 text-center">{emailError}</p>}
