              <button type="submit" className="w-full bg-cyan-400 hover:bg-white text-slate-950 font-black py-5 md:py-7 rounded-[1.5rem] md:rounded-[2rem] uppercase text-[10px] md:text-[12px] tracking-[0.4em] md:tracking-[0.6em] transition-all shadow-2xl shadow-cyan-400/20 active:scale-95">Valider l'Extraction</button>
