              <input type="password" placeholder="Clé Stellaire" value={adminPassword} onChange={e => setAdminPassword(e.target.value)} className="w-full bg-black/80 border border-white/10 rounded-[1.5rem] md:rounded-[2rem] px-8 md:px-12 py-5 md:py-7 text-[13px] md:text-[15px] text-white outline-none focus:border-cyan-400 transition-all font-black text-center" />
              <button type="submit" className="w-full bg-white text-slate-950 font-black py-5 md:py-7 rounded-[1.5rem] md:rounded-[2rem] uppercase text-[10px] md:text-[12px] tracking-[0.5em] md:tracking-[0.7em] hover:bg-cyan-400 transition-all shadow-3xl hover:scale-105 active:scale-95">Déverrouiller le Dôme</button>
              {loginError && <p className="text-red-500 text-[10px] md:text-[11px] text-center uppercase font-black tracking-widest mt-6 md:mt-10 italic">Sceau Astral Refusé</p>}
