      {isSyncing && (
        <div className="fixed inset-0 z-[10000] flex flex-col items-center justify-center bg-slate-950/98 backdrop-blur-3xl p-6">
           <div className="relative">
              <div className="w-24 md:w-32 h-24 md:h-32 border-[8px] md:border-[10px] border-cyan-500/10 border-t-cyan-500 rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                 <div className="w-3 md:w-4 h-3 md:h-4 bg-cyan-400 rounded-full animate-ping"></div>
              </div>
           </div>
           <p className="text-cyan-400 text-[12px] md:text-[14px] font-black text-center uppercase tracking-[1em] md:tracking-[2em] mt-16 md:mt-20 animate-pulse-slow">Liaison au Node Polaris...</p>
